pub struct AddressSpace {
    /// 页面表：使用 Arc<SyncUnsafeCell<PageTable>> 来确保对页面表的修改是互斥的。
    /// 这一点特别重要，因为页面表的修改通常涉及到对硬件的操作，必须确保在任一时刻只有一个线程能够修改页面表。
    /// TODO: 优化：在处理页面错误时减少锁的粒度，以提高系统的并发性能和响应速度。
    pub page_table: Arc<SyncUnsafeCell<PageTable>>,

    /// 虚拟内存区域（VMAs）：从起始虚拟页面号映射到 VMAs 的映射。
    /// VMAs 是连续的虚拟内存区域，每个区域可以有不同的权限和映射属性。
    /// 使用 BTreeMap 来存储这些区域，可以高效地进行查找和范围查询。
    pub areas: BTreeMap<VirtPageNum, VmArea>,

    /// 堆范围：这是一个可选字段，用于记录进程堆区域的虚拟地址范围。
    /// 堆是动态内存分配的区域，可以根据需要进行扩展和收缩。
    /// 在某些操作系统设计中，堆的起始地址是固定的，但最大范围可以动态调整。
    pub heap_range: Option<SimpleRange<VirtAddr>>,
}


impl AddressSpace {

        /// 创建一个空的 `AddressSpace` 实例。
    pub fn new_bare() -> Self {
        Self {
            // 使用 Arc 包装一个新的 PageTable 实例。PageTable::new() 负责创建一个新的页面表。
            // Arc 使得这个页面表可以在多个线程之间安全共享，而 SyncUnsafeCell 允许在多线程环境下进行可变访问，
            // 这是因为操作系统内核需要在不同的上下文中修改页面表。
            page_table: Arc::new(SyncUnsafeCell::new(PageTable::new())),

            // 创建一个新的、空的 BTreeMap 用于存储虚拟内存区域（VMAs）。
            // 在这个阶段，没有任何内存区域被映射，因此这个映射是空的。
            areas: BTreeMap::new(),

            // 堆范围初始化为 None，意味着初始时没有分配堆内存。
            // 这允许后续根据需要动态地分配和调整堆内存的范围。
            heap_range: None,
        }
    }


    /// 创建一个空的 `AddressSpace` 实例，但包含全局内核映射。
    pub fn new_from_global() -> Self {
        // 首先，获取全局内核地址空间的引用。
        // 这里使用了 unsafe 代码块，因为 KERNEL_SPACE 是一个静态可变引用，
        // 在 Rust 中访问静态可变引用需要使用 unsafe。
        let kernel_space = unsafe { KERNEL_SPACE.as_ref().unwrap() };

        // 创建一个新的页面表，并从内核地址空间复制所有页面表项（PTEs）。
        // 这一过程确保了新的地址空间包含了对内核空间的映射。
        let mut new_page_table = PageTable::new();
        for (_, area) in kernel_space.areas.iter() {
            let pte_flags = PTEFlags::from_bits(area.map_perm.bits()).unwrap();
            for vpn in area.vpn_range {
                let ppn = kernel_space.translate(vpn).unwrap().ppn();
                new_page_table.map(vpn, ppn, pte_flags);
            }
        }

        // 构造并返回一个新的 AddressSpace 实例。
        Self {
            page_table: Arc::new(SyncUnsafeCell::new(new_page_table)),
            areas: BTreeMap::new(),
            heap_range: None,
        }
    }

    /// 通过给定的虚拟页号查找对应的虚拟内存区域的不可变引用。
    pub fn find_vm_area_by_vpn(&self, vpn: VirtPageNum) -> Option<&VmArea> {
        // 使用范围查询来找到给定虚拟页号所属的映射区域。
        // 这里利用了 BTreeMap 的 range 方法，它允许我们高效地查询位于指定范围内的键值对。
        if let Some((_, vm_area)) = self.areas.range(..=vpn).next_back() {
            // 检查找到的虚拟内存区域的结束虚拟页号是否大于给定的虚拟页号，
            // 如果不是，说明给定的虚拟页号不在这个区域内，函数返回 None。
            if vm_area.end_vpn() <= vpn {
                return None;
            }
            // 如果给定的虚拟页号在区域内，返回这个虚拟内存区域的引用。
            Some(vm_area)
        } else {
            // 如果没有找到任何区域包含给定的虚拟页号，返回 None。
            None
        }
}

    /// 通过给定的虚拟页号查找对应的虚拟内存区域的可变引用。
    pub fn find_vm_area_mut_by_vpn(&mut self, vpn: VirtPageNum) -> Option<&mut VmArea> {
        // 首先尝试通过另一个函数 `find_vm_area_mut_by_vpn_included` 查找包含给定虚拟页号的虚拟内存区域。
        if let Some(vma) = self.find_vm_area_mut_by_vpn_included(vpn) {
            // 如果找到的虚拟内存区域的结束虚拟页号恰好等于给定的虚拟页号，
            // 根据某些设计决策，这种情况下可能不希望返回该区域（可能是因为结束虚拟页号是不包含在区域内的），
            // 因此返回 None。
            if vma.end_vpn().0 == vpn.0 {
                None
            } else {
                // 如果给定的虚拟页号确实在虚拟内存区域内，返回这个区域的可变引用。
                Some(vma)
            }
        } else {
            // 如果没有找到任何包含给定虚拟页号的虚拟内存区域，返回 None。
            None
        }
    }

    /// 通过给定的虚拟页号查找对应的虚拟内存区域的可变引用（包括结束虚拟页号）。
    pub fn find_vm_area_mut_by_vpn_included(&mut self, vpn: VirtPageNum) -> Option<&mut VmArea> {
        // 使用范围查询来找到给定虚拟页号所属的映射区域。
        // 这里利用了 BTreeMap 的 range_mut 方法来进行可变引用的范围查询，允许修改找到的区域。
        if let Some((_, vm_area)) = self.areas.range_mut(..=vpn).next_back() {
            // 检查找到的虚拟内存区域的结束虚拟页号是否小于给定的虚拟页号，
            // 如果是，说明给定的虚拟页号不在这个区域内，函数返回 None。
            if vm_area.end_vpn() < vpn {
                return None;
            }
            // 如果给定的虚拟页号在区域内或恰好是区域的结束虚拟页号，返回这个虚拟内存区域的可变引用。
            Some(vm_area)
        } else {
            // 如果没有找到任何区域包含或等于给定的虚拟页号，返回 None。
            None
        }
    }

    /// Handle page fault
    pub fn handle_page_fault(&mut self, va: VirtAddr, _scause: usize) -> Result<(), SyscallErr> {
        // There are serveral kinds of page faults:
        // 1. mmap area
