                    let mut trap_context = self.trap_context();
                    if let Some(stack) = stack {
                        trap_context.set_sp(stack);
                    }
                    trap_context
                },
                ustack_base: unsafe { (*self.inner.get()).ustack_base },
                state: ThreadStateAtomic::new(),
                // terminated: AtomicBool::new(false),
            }),
        }
    }


    /// Get the copied trap context
    pub fn trap_context(&self) -> TrapContext {
        unsafe { (*self.inner.get()).trap_context }
    }

    /// Get the mutable ref of trap context
    pub fn trap_context_mut(&self) -> &mut TrapContext {
        unsafe { &mut (*self.inner.get()).trap_context }
    }

    /// Terminate this thread
    pub fn terminate(&self) {
        unsafe {
            (*self.inner.get()).state.store(ThreadState::Zombie);
        }
    }
    /// Whether this thread has been terminated or not
    pub fn is_zombie(&self) -> bool {
        unsafe { (*self.inner.get()).state.load() == ThreadState::Zombie }
    }
    /// Tid of this thread
    pub fn tid(&self) -> usize {
        self.tid.0
    }
}

/// Yield the current thread (and the scheduler will switch to next thread)
pub async fn yield_now() {
    schedule::YieldFuture(false).await;
}

/// Spawn a new user thread
pub fn spawn_thread(thread: Arc<Thread>) {
    // let future = schedule::OutermostFuture::new(thread.clone(), async {});
    let future = schedule::UserTaskFuture::new(thread.clone(), threadloop(thread));
    let (runnable, task) = task::task_queue::spawn(future);
    runnable.schedule();
    task.detach();
}

use super::Thread;
use crate::{task::smp::current_task, task::thread::exit::handle_exit, trap};
use alloc::sync::Arc;
use log::debug;

pub async fn threadloop(thread: Arc<Thread>) {
    debug!("into thread loop");
    loop {
        // println!("pid {} back to threadloop", current_process().get_pid());
        // return to user mode
        let trap_context = unsafe {
            // TODO: figure out why we can't use in this way
            // &mut (*thread.inner.get()).trap_context
            let p = &mut *thread.inner.get();
            &mut p.trap_context
        };
        // let trap_context = thread.task.inner_exclusive_access().get_trap_cx();
        // // TODO: not sure whther `exclusive access` leads to deadlock
        trap::trap_handler::trap_return(trap_context);
        // println!("trap from user");
        // next time when user traps into kernel, it will come back here
        trap::trap_handler::trap_handler().await;

        if thread.is_zombie() {
            debug!("thread {} terminated", current_task().tid());
            break;
        }
    }

    // When the process becomes zombie, all of its threads should exit too
    handle_exit(&thread);
}

