pub struct YieldFuture(pub bool);

impl Future for YieldFuture {
    type Output = ();

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context) -> Poll<Self::Output> {
        if self.0 {
            return Poll::Ready(());
        }
        self.0 = true;
        // Wake up this future, which means putting this thread into
        // the tail of the task queue
        cx.waker().wake_by_ref();
        Poll::Pending
    }
}

/// The outermost future, i.e. the future that wraps
/// one thread's task future(doing some env context changes e.g.
/// pagetable switching)
pub struct UserTaskFuture<F: Future + Send + 'static> {
    task_ctx: LocalContext,
    task_future: F,
}

impl<F: Future + Send + 'static> UserTaskFuture<F> {
    #[inline]
    pub fn new(thread: Arc<Thread>, future: F) -> Self {
        let task_ctx = TaskContext {
            thread: thread.clone(),
            page_table: thread.process.inner.lock().memory_set.page_table.clone(),
            env: EnvContext::new(),
        };
        let task_ctx = Box::new(task_ctx);
        let local_ctx = LocalContext::TaskContext(task_ctx);
        Self {
            task_ctx: local_ctx,
            task_future: future,
        }
    }
}

impl<F: Future + Send + 'static> Future for UserTaskFuture<F> {
    type Output = F::Output;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = unsafe { self.get_unchecked_mut() };
        // let this = self.get_mut();
        let hart = smp::local_hart();
        hart.push_task(&mut this.task_ctx);
        let ret = unsafe { Pin::new_unchecked(&mut this.task_future).poll(cx) };
        hart.pop_task(&mut this.task_ctx);

        ret
    }
}

use alloc::collections::VecDeque;
use async_task::{Runnable, Task};
use core::future::Future;
use lazy_static::*;
use spin::mutex::SpinMutex;

struct TaskQueue {
    queue: SpinMutex<VecDeque<Runnable>>,
}

impl TaskQueue {
    pub fn new() -> Self {
        Self {
            queue: SpinMutex::new(VecDeque::new()),
        }
    }
    pub fn push_task(&self, runnable: Runnable) {
        self.queue.lock().push_back(runnable);
    }
    pub fn fetch_task(&self) -> Option<Runnable> {
        self.queue.lock().pop_front()
    }
}

lazy_static! {
    static ref TASK_QUEUE: TaskQueue = TaskQueue::new();
}

/// 将一个任务加入执行器
pub fn spawn<F>(future: F) -> (Runnable, Task<F::Output>)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    async_task::spawn(future, |runnable| {
        TASK_QUEUE.push_task(runnable);
    })
}

pub fn run_until_idle() {
    loop {
        if let Some(task) = TASK_QUEUE.fetch_task() {
            task.run();
        } else {
            break;
        }
    }
}

