/// Store some permission flags
pub struct EnvContext {
    sum: usize,
}

impl EnvContext {
    pub const fn new() -> Self {
        Self { sum: 0 }
    }

    pub fn sum_inc(&mut self) {
        if self.sum == 0 {
            unsafe {
                sstatus::set_sum();
            }
        }
        self.sum += 1
    }

    pub fn sum_dec(&mut self) {
        if self.sum == 1 {
            unsafe {
                sstatus::clear_sum();
            }
        }
        self.sum -= 1
    }

    pub fn env_change(new: &mut Self, old: &mut Self) {
        unsafe {
            if (new.sum > 0) != (old.sum > 0) {
                if new.sum > 0 {
                    sstatus::set_sum();
                } else {
                    sstatus::clear_sum();
                }
            }
            sstatus::clear_sie();
        }
    }
}

