use riscv::register::sstatus::{self, Sstatus, SPP};

/// Trap context structure containing sstatus, sepc and registers
#[repr(C)]
#[derive(Clone, Copy)]
pub struct TrapContext {
    /// user-to-kernel should save:
    /// general regs[0..31]
    pub user_x: [usize; 32],
    /// CSR sstatus      
    pub sstatus: Sstatus, // 32
    /// CSR sepc
    pub sepc: usize, // 33

    /// kernel-to-user should save:
    pub kernel_sp: usize, // 34
    ///
    pub kernel_ra: usize, // 35
    ///
    pub kernel_s: [usize; 12], // 36 - 47
    ///
    pub kernel_fp: usize, // 48
}

impl TrapContext {
    ///set stack pointer to x_2 reg (sp)
    pub fn set_sp(&mut self, sp: usize) {
        self.user_x[2] = sp;
    }
    ///init app context
    pub fn app_init_context(entry: usize, sp: usize) -> Self {
        let mut sstatus = sstatus::read();
        // set CPU privilege to User after trapping back
        sstatus.set_spp(SPP::User);
        let mut cx = Self {
            user_x: [0; 32],
            sstatus,
            sepc: entry,
            kernel_sp: 0,
            kernel_ra: 0,
            kernel_s: [0; 12],
            kernel_fp: 0,
        };
        cx.set_sp(sp);
        cx
    }
}

use crate::{
    mm::address::VirtAddr,
    syscall::syscall,
    task::smp::{current_process, current_trap_cx},
    task::thread::exit::exit_and_terminate_all_threads,
    timer::set_next_trigger,
};
use core::arch::global_asm;
use riscv::register::{
    mtvec::TrapMode,
    scause::{self, Exception, Interrupt, Trap},
    sie, stval, stvec,
};

use super::context::TrapContext;

global_asm!(include_str!("trap.S"));

extern "C" {
    fn __alltraps();
}

/// 初始化，设置 trap 处理函数入口
pub fn init() {
    set_user_trap_entry();
}

#[inline]
pub fn set_user_trap_entry() {
    unsafe {
        stvec::write(__alltraps as usize, TrapMode::Direct);
    }
}

#[inline]
/// enable timer interrupt in sie CSR
pub fn enable_timer_interrupt() {
    unsafe {
        sie::set_stimer();
    }
}

/// trap 处理函数
#[no_mangle]
pub async fn trap_handler() {
    let scause = scause::read();
    let stval = stval::read();
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            // get system call return value
            let result = syscall(
                cx.user_x[17],
                [
                    cx.user_x[10],
                    cx.user_x[11],
                    cx.user_x[12],
                    cx.user_x[13],
                    cx.user_x[14],
                    cx.user_x[15],
                ],
            )
            .await;
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.user_x[10] = match result {
                Ok(ret) => ret as usize,
                Err(err) => -(err as isize) as usize,
            }
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            match current_process().inner_handler(|proc| {
                let va = VirtAddr::from(stval);
                proc.memory_set.handle_page_fault(va, scause.bits())
            }) {
                Ok(()) => {}
                Err(_) => {
                    exit_and_terminate_all_threads(-2);
                }
            }
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            set_next_trigger();
            crate::task::thread::yield_now().await
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }
}

#[no_mangle]
pub fn trap_return(trap_context: &mut TrapContext) {
    set_user_trap_entry();
    extern "C" {
        fn __restore(cx: *mut TrapContext);
    }
    unsafe {
        __restore(trap_context);
    }
}

