// 获取当前工作目录，并将其复制到用户提供的缓冲区中
pub fn sys_getcwd(buf: usize, len: usize) -> Result<isize, SyscallErr> {
    // 创建一个作用域保护变量
    let _sum_guard = SumGuard::new();

    // 获取当前进程的工作目录
    let cwd = current_process().inner_handler(move |proc| proc.cwd.clone());

    // 检查用户提供的缓冲区是否可写，并且长度足够
    UserCheck::new().check_writable_slice(buf as *mut u8, len)?;

    // 如果提供的缓冲区长度小于工作目录路径的长度，则返回错误
    if len < cwd.len() {
        return Err(SyscallErr::BufferTooSmall);
    } else {
        // 安全地将用户提供的地址转换为可变切片
        let new_buf = unsafe { core::slice::from_raw_parts_mut(buf as *mut u8, cwd.len()) };
        // 将当前工作目录的路径复制到用户提供的缓冲区中
        new_buf.copy_from_slice(cwd.as_bytes());

        // 返回缓冲区的地址作为成功的结果
        Ok(buf as isize)
    }
}

/// 函数创建一个新的管道，并将管道的两个文件描述符（读和写）写入用户提供的缓冲区。  
/// 如果成功，函数返回0；否则返回一个SyscallErr错误。
pub fn sys_pipe2(pipe: *mut i32) -> Result<isize, SyscallErr> {
    // 调用make_pipe函数创建一个新的管道，并获取读和写两端的文件描述符
    let (pipe_read, pipe_write) = make_pipe();

    // 在当前进程的内部处理函数中，为管道的读和写端分配文件描述符，并将它们添加到文件描述符表中
    let (read_fd, write_fd) = current_process().inner_handler(move |proc| {
        let read_fd = proc.fd_table.alloc_fd();
        proc.fd_table.put(read_fd, pipe_read);
        let write_fd = proc.fd_table.alloc_fd();
        proc.fd_table.put(write_fd, pipe_write);
        // 返回这两个文件描述符
        (read_fd, write_fd)
    });

    // 验证用户提供的缓冲区是否可写，并且大小足够存储两个i32类型的值
    UserCheck::new().check_writable_slice(pipe as *mut u8, core::mem::size_of::<i32>() * 2)?;

    // 创建一个作用域保护变量
    let _sum_guard = SumGuard::new();

    // 将用户提供的指针转换为指向两个i32值的可变切片
    let buf = unsafe { core::slice::from_raw_parts_mut(pipe, 2 * core::mem::size_of::<i32>()) };

    // 将读和写文件描述符转换为i32类型，并存储在用户提供的缓冲区中
    buf[0] = read_fd as i32;
    buf[1] = write_fd as i32;

    // 返回成功的结果，表示操作成功完成
    Ok(0)
}

// 复制文件描述符
pub fn sys_dup(oldfd: usize) -> Result<isize, SyscallErr> {
    // 获取当前进程，并尝试复制文件描述符
    let newfd = current_process()
        .inner_handler(move |proc| {
            // 尝试从进程的文件描述符表中获取oldfd的引用
            if let Some(file) = proc.fd_table.get_ref(oldfd).cloned() {
                // 如果找到，则分配一个新的文件描述符
                let newfd = proc.fd_table.alloc_fd();
                // 将旧文件描述符对应的文件对象关联到新的文件描述符上
                proc.fd_table.put(newfd, file);
                // 返回新文件描述符
                Some(newfd)
            } else {
                // 如果未找到oldfd，返回None
                None
            }
        })
        // 如果操作失败（例如oldfd不存在），则返回一个错误
        .ok_or(SyscallErr::InvalidFileDescriptor)?;
    // 操作成功，返回新文件描述符
    Ok(newfd as isize)
}

// 复制文件描述符，并允许指定新文件描述符的值，同时设置额外的标志
pub fn sys_dup3(oldfd: usize, newfd: usize, flags: u32) -> Result<isize, SyscallErr> {
    // TODO: 处理`close on exec`标志
    current_process().inner_handler(move |proc| {
        // 尝试获取oldfd对应的文件对象
        if let Some(file) = proc.fd_table.get(oldfd) {
            // 检查newfd是否有效
            if newfd >= RLIMIT_NOFILE {
                // 如果newfd超出了文件描述符的限制，返回错误
                return Err(SyscallErr::InvalidFileDescriptor);
            }
            // 尝试释放newfd指向的文件描述符（如果存在）
            if proc.fd_table.take(newfd).is_none() {
                // 如果newfd未被占用，为它分配指定的文件描述符
                proc.fd_table.alloc_spec_fd(newfd);
            }
            // 将oldfd对应的文件对象关联到newfd
            proc.fd_table.put(newfd, file.clone());
            // 操作成功，返回新文件描述符
            Ok(newfd as isize)
        } else {
            Err(SyscallErr::InvalidFileDescriptor)
        }
    })
}

/// 更改调用进程的当前工作目录到指定路径。
pub fn sys_chdir(path: *const u8) -> Result<isize, SyscallErr> {
    let _sum_guard = SumGuard::new();
    // 确保路径字符串是有效的C字符串
    UserCheck::new().check_c_str(path)?;

    // 在no_std环境下，我们假设c_str_to_string可以转换C字符串为Rust字符串
    // 注意：在no_std环境下，通常需要手动实现这样的转换，因为String类型不可用
    let path_str = c_str_to_string(path); // 这需要是一个自定义函数，因为no_std不支持String

    // 从根目录开始查找目标inode，这里假设lookup_from_root是一个静态方法，不依赖于std库
    let target_inode = <dyn Inode>::lookup_from_root(&path_str);
    match target_inode {
        Some(target_inode) => {
            // 更新访问时间
            target_inode.metadata().inner.lock().st_atime = (get_time_ms() / 1000) as i64;
            // 检查目标inode是否为目录
            if target_inode.metadata().mode == InodeMode::FileDIR {
                // 更新当前进程的工作目录
                // 注意：在no_std环境下，我们无法使用to_string()，因此需要使用其他方式来复制路径字符串
                current_process().inner_handler(move |proc| {
                    proc.cwd = path_str; // 假设proc.cwd可以存储路径字符串的形式
                });
                Ok(0)
            } else {
                Err(SyscallErr::NotADirectory)
            }
        }
        None => Err(SyscallErr::NoEntry),
    }
}

/// 打开或创建一个文件，并返回一个文件描述符。
pub fn sys_openat(
    dirfd: usize,
    filename_addr: *const u8,
    flags: u32,
    _mode: u32,
) -> Result<isize, SyscallErr> {
    let absolute_path: Option<String>;
    if dirfd as isize == -100 {
        absolute_path = path_utils::path_process(filename_addr);
    } else {
        absolute_path = path_utils::path_with_dirfd(dirfd as isize, filename_addr);
    }

    let flags = OpenFlags::from_bits(flags).ok_or(SyscallErr::OtherError)?;
    match absolute_path {
        Some(absolute_path) => {
            if let Some(inode) = fs::vfs::inode::open_file(absolute_path.as_str(), flags) {
                // 更新文件访问时间
                inode.metadata().inner.lock().st_atime = (get_time_ms() / 1000) as i64;
                let fd = current_process().inner_handler(|proc| {
                    let fd = proc.fd_table.alloc_fd();
                    let file = inode.open(inode.clone(), flags)?;
                    proc.fd_table.put(fd, file);
                    Ok(fd)
                })?;
                Ok(fd as isize)
            } else {
                Err(SyscallErr::OtherError)
            }
        }
        None => Err(SyscallErr::OtherError),
    }
}

pub fn sys_close(fd: usize) -> Result<isize, SyscallErr> {
    let process = current_process();
    return process.inner_handler(move |proc| {
        // 尝试从进程的文件描述符表中移除指定的文件描述符
        if proc.fd_table.take(fd).is_none() {
            // 如果指定的文件描述符不存在，则返回一个具体的错误
            Err(SyscallErr::InvalidFileDescriptor)
        } else {
            // 如果成功移除，表示文件描述符有效且关闭操作成功
            Ok(0)
        }
    });
}

