/// 创建一个新的进程或线程。
///
/// 根据提供的标志，此函数可以克隆当前进程创建一个新进程，或者在同一进程内创建一个新线程。
///
/// # 参数
///
/// * `flags` - 克隆标志，决定克隆行为的细节。
/// * `stack` - 新创建的进程或线程的栈顶指针。
/// * `ptid` - 未使用，保留参数。
/// * `tls` - 未使用，保留参数。
/// * `ctid` - 未使用，保留参数。
///
/// # 返回值
///
/// 成功时返回新进程或线程的 PID
pub fn sys_clone(
    flags: usize,
    stack: *const u8,
    ptid: *const u8,
    tls: *const u8,
    ctid: *const u8,
) -> Result<isize, SyscallErr> {
    bitflags! {
        ///Open file flags
        pub struct CloneFlags: u32 {
            const CLONE_THREAD = 1 << 4;
            const CLONE_VM = 1 << 8;
            const CLONE_FS = 1 << 9;
            const CLONE_FILES = 1 << 10;
        }
    }

    // 尝试将 flags 转换为 CloneFlags 枚举
    let clone_flags = CloneFlags::from_bits(flags.try_into().unwrap());

    // 检查 flags 是否有效
    if clone_flags.is_none() && flags != 17 {
        return Err(SyscallErr::OtherError);
    }

    let clone_flags = {
        // 特殊情况处理：如果 flags 为 17，则将其视为没有任何克隆标志
        if flags == 17 as usize {
            CloneFlags::from_bits(0).unwrap()
        } else {
            clone_flags.unwrap()
        }
    };

    // 根据克隆标志决定是创建新进程还是新线程
    if !clone_flags.contains(CloneFlags::CLONE_THREAD) {
        // 创建新进程（类似于 fork）

        let current_process = current_process();
        // 如果提供了栈地址，则使用提供的地址，否则为 None
        let stack = match stack as usize {
            0 => None,
            _ => Some(stack as usize),
        };
        // 使用 fork 方法创建新进程
        let new_process = current_process.fork(stack)?;
        let new_pid = new_process.pid();

        // 修改新进程的陷阱上下文，使其在切换后立即返回
        let trap_cx = new_process.trap_context_main();
        trap_cx.user_x[10] = 0; // 对于子进程，fork 返回 0

        Ok(new_pid as isize)
    } else {
        // 创建新线程（类似于 clone）
        let current_process = current_process();
        // 创建新线程
        current_process.create_thread(stack as usize)
    }
}

/// 执行指定路径的程序，并传递命令行参数。
///
/// # 参数
///
/// * `path` - 指向程序路径的指针。
/// * `args` - 指向命令行参数的指针数组。
///
/// # 返回值
///
/// 成功时返回新程序的 PID
pub fn sys_execve(path: *const u8, mut args: *const usize) -> Result<isize, SyscallErr> {
    // 允许内核访问用户空间
    let _sum_guard = SumGuard::new();

    // 转换命令行参数
    let mut args_vec: Vec<String> = Vec::new();
    while unsafe { *args != 0 } {
        let arg_ptr = unsafe { *args } as *const u8;
        let arg_str = c_str_to_string(arg_ptr);
        args_vec.push(arg_str);
        unsafe {
            args = args.add(1);
        }
    }

    // 检查路径字符串的有效性
    UserCheck::new().check_c_str(path)?;
    let path_str = c_str_to_string(path);

    // 特殊情况处理：如果路径是 "shell"，则尝试从已知位置加载 shell 程序
    if path_str == "shell" {
        if let Some(elf_data) = get_app_data_by_name("shell") {
            return current_process().exec(elf_data, args_vec);
        } else {
            return Err(SyscallErr::OtherError);
        }
    }

    // 尝试打开指定路径的文件
    match fs::fat32fs::root_fs::open_file(&path_str, OpenFlags::RDONLY) {
        Some(app_inode) => {
            let elf_data = app_inode.read_all();
            current_process().exec(&elf_data, args_vec)
        },
        None => {
            Err(SyscallErr::OtherError)
        }
    }
}

/// 等待指定 PID 的子进程结束，并获取其退出状态。
///
/// 如果没有与给定 PID 相匹配的子进程，返回 -1。
/// 如果有相匹配的子进程但它仍在运行中，返回 -2。
///
/// # 参数
///
/// * `pid` - 指定的子进程 PID。如果 PID 为 -1，则等待任何一个子进程。
/// * `exit_status_addr` - 退出状态的用户空间地址，如果不为 0，则将退出状态写入该地址。
///
/// # 返回值
///
/// 成功时返回子进程的 PID
pub async fn sys_wait4(pid: isize, exit_status_addr: usize) -> Result<isize, SyscallErr> {
    let process = current_process();

    // 如果 exit_status_addr 不为 0，检查该地址是否可写
    if exit_status_addr != 0 {
        UserCheck::new()
            .check_writable_slice(exit_status_addr as *mut u8, core::mem::size_of::<i32>())?;
    }

    loop {
        // 在当前进程的上下文中处理
        let ret = process.inner_handler(move |proc| {
            // 查找匹配的子进程
            if !proc
                .children
                .iter()
                .any(|p| pid == -1 || pid as usize == p.pid())
            {
                // 如果没有找到匹配的子进程
                if pid == -1 && proc.children.is_empty() {
                    // 如果 PID 为 -1 且没有子进程，视为系统退出
                    return Ok(-3);
                }
                return Err(SyscallErr::OtherError);
            }

            // 查找已成为僵尸状态的子进程
            let idx = proc
                .children
                .iter()
                .enumerate()
                .find(|(_, p)| p.is_zombie() && (pid == -1 || pid as usize == p.pid()))
                .map(|(idx, _)| idx);

            if let Some(idx) = idx {
                // 如果找到了已成为僵尸的子进程
                let child = proc.children.remove(idx);
                let found_pid = child.pid();
                let exit_code = child.exit_code();

                // 如果提供了 exit_status_addr，将退出状态写入用户空间
                if exit_status_addr != 0 {
                    let _sum_guard = SumGuard::new();
                    let exit_status_ptr = exit_status_addr as *mut i32;
                    unsafe {
                        exit_status_ptr.write_volatile((exit_code as i32 & 0xff) << 8);
                    }
                }
                Ok(found_pid as isize)
            } else {
                // 如果子进程仍然存活，返回 -1
                Ok(-1 as isize)
            }
        })?;

        match ret {
            -1 => {
                // 如果子进程还在运行，让出 CPU 并重新尝试
                crate::syscall::process::thread::yield_now().await;
            },
            -3 => {
                // 如果是系统退出，终止所有线程并退出
                exit_and_terminate_all_threads(0);
                return Ok(ret);
            },
            _ => {
                // 如果成功获取到了子进程的退出状态，返回子进程的 PID
                return Ok(ret);
            }
        }
    }
}

// 系统调用：退出当前线程
pub fn sys_exit(exit_code: i8) -> Result<isize, SyscallErr> {
    // 获取当前线程的线程ID
    let tid = local_hart().current_task().tid();

    // 终止指定线程并传入退出码
    terminate_given_thread(tid, exit_code);

    // 返回成功状态
    Ok(0)
}

/// 获取当前进程的父进程标识符（PPID）。
///
/// # 返回值
///
/// 如果当前进程是初始进程，则返回 1，表示没有父进程。
pub fn sys_getppid() -> Result<isize, SyscallErr> {
    // 获取当前进程的实例
    let current_process = current_process();

    // 通过对当前进程实例的内部处理，获取其父进程
    let parent_process = current_process.inner_handler(|proc| proc.parent.clone());

    match parent_process {
        // 如果存在父进程，尝试提升弱引用并获取 PID
        Some(parent_process) => {
            Ok(parent_process.upgrade().expect("Failed to upgrade parent process").pid() as isize)
        },
        // 如果不存在父进程（即，当前进程为初始进程），则按惯例返回 1
        None => Ok(1),
    }
}

/// 获取当前进程的进程标识符（PID）。
///
/// # 返回值
///
/// 返回当前进程的 PID
pub fn sys_getpid() -> Result<isize, SyscallErr> {
    // 直接通过 `current_task` 函数获取当前任务的引用，
    // 并进一步获取其进程的 PID，将其转换为 isize 类型
    Ok(current_task().as_ref().process.pid() as isize)
}

