/// sys_mmap 函数用于在进程的地址空间中创建新的内存映射。  
///  
/// 参数:  
/// - addr: 建议的映射起始地址
/// - length: 要映射的内存区域长度（以字节为单位）。  
/// - prot: 保护标志，表示映射区域的保护权限
/// - flags: 映射标志，控制映射的特性和行为 
/// - fd: 文件描述符，指定要映射的文件
/// - offset: 文件内的偏移量，指定从文件的哪个位置开始映射。  
///  
/// 返回值:  
/// - Result<isize, SyscallErr>: 如果映射成功，返回映射区域的起始地址（作为 isize 类型）；  
///   如果发生错误，则返回包含错误信息的 Err(SyscallErr)。  
pub fn sys_mmap(  
    addr: *const u8,   
    length: usize,   
    prot: i32,       
    flags: i32,      
    fd: usize,        
    offset: usize,
) -> Result<isize, SyscallErr> {  

    // 辅助函数，用于从保护标志推导映射权限  
    let derive_map_permissions = |protection_flags: MmapProt| -> MapPermission {  
        let mut permissions = MapPermission::from_bits(0).unwrap();  
        if protection_flags.contains(MmapProt::PROT_READ) {  
            permissions |= MapPermission::R;  
        }  
        if protection_flags.contains(MmapProt::PROT_WRITE) {  
            permissions |= MapPermission::W;  
        }  
        if protection_flags.contains(MmapProt::PROT_EXEC) {  
            permissions |= MapPermission::X;  
        }  
        permissions  
    };  

    // 从 i32 类型的保护标志转换为 MmapProt 枚举类型  
    let protection_flags = MmapProt::from_bits(prot as u32).ok_or(SyscallErr::InvalidProtFlags)?;  

    // 从 i32 类型的映射标志转换为 MmapFlags 枚举类型  
    let map_flags = MmapFlags::from_bits(flags as u32).ok_or(SyscallErr::InvalidFlag)?;  

    // 如果设置了 MAP_ANONYMOUS 标志，表示创建匿名映射（不关联任何文件）  
    if map_flags.contains(MmapFlags::MAP_ANONYMOUS) {  
        todo!("匿名映射的实现尚未完成")  
    } else {  
        // 在当前进程的上下文中执行映射操作  
        current_process().inner_handler(|process| {  
            // 通过文件描述符获取文件句柄  
            let file_handle = process.fd_table.get(fd).ok_or(SyscallErr::InvalidFileDescriptor)?;  

            // 从保护标志推导映射权限  
            let permissions = derive_map_permissions(protection_flags);  

            // 在进程的内存集中查找可用的内存区域  
            let mut virtual_memory_area = process  
                .memory_set  
                .find_unused_area(length, permissions)  
                .ok_or(SyscallErr::NoMemoryAvailable)?;  

            // 设置内存区域的映射标志 
            virtual_memory_area.mmap_flags = Some(map_flags);  

            // 创建一个页面错误处理程序的实例，并将其设置为内存区域的处理程序  
            let page_fault_handler = MmapPageFaultHandler {};  
            virtual_memory_area.handler = Some(page_fault_handler.box_clone());  

            // 设置内存区域的备份文件信息（如果需要从文件映射）  
            virtual_memory_area.backup_file = Some(BackupFile {  
                offset: offset,  
                file: file_handle.clone(),  
            });  

            // 将内存区域插入进程的内存集，并返回映射区域的起始地址  
            let start_address: VirtAddr = virtual_memory_area.start_vpn().into();  
            process.memory_set.insert_area(virtual_memory_area);  

            // 将起始地址转换为 isize 类型并返回  
            Ok(start_address.0 as isize)  
        })  
    }  
}

