//! 此文件用于fat32文件系统的初始化和有文件操作相关的函数

use crate::{
    driver::block::{io_device::IoDevice, BLOCK_DEVICE},
    fs::{
        fat32fs::{fat32fs::Fat32FileSystem, file::Fat32File, inode::Fat32NodeType},
        open_flags::OpenFlags,
        vfs::{
            file_system::{FileSystem, FileSystemType},
            inode::InodeMode,
        },
    },
    klib::error::SyscallErr,
};
use alloc::sync::Arc;
use lazy_static::*;

lazy_static! {
    /// 一个 Fat32FileSystem 类型的引用，被 lazy_static 宏包裹，意味着它在第一次被访问时才会初始化。
    pub static ref ROOT_FS: Fat32FileSystem = {
        let buffer_cache = IoDevice::new(BLOCK_DEVICE.clone());
        let filesystem = Fat32FileSystem::new(buffer_cache);
        filesystem
    };
}

pub fn open_file(name: &str, flags: OpenFlags) -> Option<Arc<Fat32File>> {
    // 获取读写标志
    let (readable, writable) = flags.read_write();
    // 获取根目录
    let root_dir = ROOT_FS.fat_fs.root_dir();

    // 尝试打开文件
    let inode_result = root_dir.open_file(name);

    if flags.contains(OpenFlags::CREATE) {
        match inode_result {
            Ok(inode) => Some(Arc::new(Fat32File::new(
                Fat32NodeType::File(inode),
                None,
                readable,
                writable,
            ))),
            Err(_) => {
                // 如果打开失败，则创建文件
                let created_inode = root_dir.create_file(name).expect("Failed to create file");
                Some(Arc::new(Fat32File::new(
                    Fat32NodeType::File(created_inode),
                    None,
                    readable,
                    writable,
                )))
            }
        }
    } else {
        // 如果不需要创建文件，则返回打开的结果
        inode_result.ok().map(|inode| {
            Arc::new(Fat32File::new(
                Fat32NodeType::File(inode),
                None,
                readable,
                writable,
            ))
        })
    }
}

pub fn init() -> Result<(), SyscallErr> {
    // 初始化文件系统
    ROOT_FS.init_ref("/", FileSystemType::VFAT)?;
    // 获取根节点
    let root_inode = ROOT_FS.metadata().root_inode.expect("Root inode not found");
    // 在根节点下创建名为 "mnt" 的目录
    root_inode.mkdir(root_inode.clone(), "mnt", InodeMode::FileDIR)?;
    Ok(())
}

