        unsafe { (*self.meta.get()).as_ref().unwrap().clone() }
    }
    /// 这个方法也用于设置文件系统的元数据。
    fn set_metadata_ref(&self, metadata: FileSystemMeta) {
        unsafe {
            *self.meta.get() = Some(metadata);
        }
    }
}

//! 此文件用于对fat32文件系统的节点进行操作

use crate::{
    driver::block::io_device::IoDevice,
    fs::{
        fat32fs::file::Fat32File,
        open_flags::OpenFlags,
        vfs::{
            file::{File, FileMeta, FileMetaInner},
            inode::{Inode, InodeMeta, InodeMode, INODE_CACHE},
        },
    },
    klib::error::SyscallErr,
};
use alloc::string::ToString;
use alloc::sync::Arc;
use fatfs::DirEntry;
use log::debug;
use spin::mutex::SpinMutex;

/// 用于表示 FAT32 文件系统中的节点类型。
pub enum Fat32NodeType {
    Dir(),
    File(fatfs::File<'static, IoDevice, fatfs::DefaultTimeProvider, fatfs::LossyOemCpConverter>),
}
/// 用于表示 FAT32 文件系统中的节点。
pub struct Fat32Inode {
    pub dentry: DirEntry<'static, IoDevice, fatfs::DefaultTimeProvider, fatfs::LossyOemCpConverter>,
    pub meta: Option<InodeMeta>,
}
/// 实现了 Send 和 Sync trait，表示该结构体是线程安全的，可以安全地在多线程环境中发送或共享。
unsafe impl Send for Fat32Inode {}
unsafe impl Sync for Fat32Inode {}
/// 用于生成一个新的fat32节点。
impl Fat32Inode {
    pub fn new(
        dentry: DirEntry<'static, IoDevice, fatfs::DefaultTimeProvider, fatfs::LossyOemCpConverter>,
        meta: Option<InodeMeta>,
    ) -> Self {
        Self { dentry, meta }
    }
}

impl Inode for Fat32Inode {
    /// 进行文件的打开。
    fn open(&self, this: Arc<dyn Inode>, flags: OpenFlags) -> Result<Arc<dyn File>, SyscallErr> {
        debug!("[Fat32Inode]: open: name: {}", self.dentry.file_name());
        let (readable, writable) = flags.read_write();
        let file_meta = FileMeta {
            path: self.dentry.file_name(),
            flags,
            inner: SpinMutex::new(FileMetaInner {
                inode: Some(this),
                pos: 0,
            }),
        };

        let file = match self.dentry.is_dir() {
            true => Fat32File::new(Fat32NodeType::Dir(), Some(file_meta), readable, writable),
            false if self.dentry.is_file() => Fat32File::new(
                Fat32NodeType::File(self.dentry.to_file()),
                Some(file_meta),
                readable,
                writable,
            ),
            _ => return Err(SyscallErr::OtherError),
        };

        Ok(Arc::new(file))
    }
    /// 返回当前节点的元数据信息的引用。
    fn metadata(&self) -> &InodeMeta {
        self.meta.as_ref().expect("Metadata is not set")
    }
    /// 接受一个参数 meta，用于设置当前节点的元数据信息。
    fn set_metadata(&mut self, meta: InodeMeta) {
        self.meta = Some(meta);
    }
    /// 加载当前目录下的所有子节点。
    fn load_children(&self, this: Arc<dyn Inode>) {
        if self.dentry.is_file() {
            panic!("Cannot load a file's children");
        }
        let mut meta_inner = self
            .meta
            .as_ref()
            .expect("Metadata is not set")
            .inner
            .lock();
        for dentry in self.dentry.to_dir().iter() {
            let dentry_ref = dentry.as_ref().expect("Failed to get dentry reference");
            let inode_mode = if dentry_ref.is_dir() {
                InodeMode::FileDIR
            } else {
                InodeMode::FileREG
            };
            let data_len = dentry_ref.len();
            let file_name = dentry_ref.file_name();

            let child_meta = InodeMeta::new(
                Some(this.clone()),
                &file_name,
                inode_mode,
                data_len as usize,
            );
            let child_inode = Arc::new(Fat32Inode::new(dentry.unwrap(), Some(child_meta)));

            meta_inner.children.insert(file_name.clone(), child_inode);
        }
    }
    /// 提供了删除子节点的功能。
    fn delete_child(&self, child_name: &str) {
        if let Err(_) = self.dentry.to_dir().remove(child_name) {}
    }
    /// 在文件系统中创建新的节点，并将其添加到相应的目录中。
    fn mknod(
        &self,
        this: Arc<dyn Inode>,
        pathname: &str,
        mode: InodeMode,
        _dev_id: usize,
    ) -> Result<(), SyscallErr> {
        if self.dentry.is_file() {
            return Err(SyscallErr::OtherError);
        }

        let name = pathname.to_string();
        self.dentry
            .to_dir()
            .create_file(&name)
            .expect("Failed to create file");

        let new_dentry = self
            .dentry
            .to_dir()
            .iter()
            .find(|dentry| dentry.as_ref().unwrap().file_name() == name)
            .expect("Failed to find new dentry")
            .unwrap();

        let mut new_inode = Fat32Inode::new(new_dentry, None);
        new_inode.init(Some(this.clone()), pathname, mode, 0)?;

        let key = new_inode.metadata().inner.lock().hash_name.name_hash as usize;
        let new_inode = Arc::new(new_inode);

        INODE_CACHE.lock().insert(key, new_inode.clone());
        this.metadata()
            .inner
            .lock()
            .children
            .insert(name, new_inode);

        Ok(())
    }
}

//! 此文件用于对fat32文件进行操作
//!
//!
use super::inode::Fat32NodeType;
use crate::{
    fs::vfs::file::{File, FileMeta},
    klib::error::SyscallErr,
    task::smp::env::SumGuard,
};
use alloc::{boxed::Box, vec::Vec};
use async_trait::async_trait;
use fatfs::{Read, Seek, Write};
use spin::mutex::SpinMutex;

/// 表示一个 FAT32 文件对象，具有读写权限和元数据。
pub struct Fat32File {
    readable: bool,
    writable: bool,
    inner: SpinMutex<Fat32FileInner>,
    meta: Option<FileMeta>,
}

/// 表示一个 FAT32 文件对象，具有读写权限和元数据。
struct Fat32FileInner {
    offset: usize,
    node: Fat32NodeType,
}
/// 这意味着 Fat32File 类型的实例可以安全地在线程之间传递，因为它是发送（Send）到其他线程的。
unsafe impl Send for Fat32File {}
/// 这表示 Fat32File 类型的实例可以安全地在多个线程之间共享，因为它是同步（Sync）的。
unsafe impl Sync for Fat32File {}

impl Fat32File {
    /// 用于创建新的 Fat32File 实例。
    pub fn new(
        node: Fat32NodeType,
        meta: Option<FileMeta>,
        readable: bool,
        writable: bool,
    ) -> Self {
        Self {
            readable,
            writable,
            meta,
            inner: SpinMutex::new(Fat32FileInner { offset: 0, node }),
        }
    }

    /// 法用于从文件中读取所有数据，并将其存储到一个向量中。
    pub fn read_all(&self) -> Vec<u8> {
        let mut inner = self.inner.lock();
        let mut buffer = [0u8; 512];
        let mut v: Vec<u8> = Vec::new();

        loop {
            let len = match &mut inner.node {
                Fat32NodeType::Dir() => panic!("Directories cannot be read as files"),
                Fat32NodeType::File(file) => file.read(&mut buffer).expect("Failed to read file"),
            };
            if len == 0 {
                break;
            }
            inner.offset += len;
            v.extend_from_slice(&buffer[..len]);
        }

        v
    }
}

#[async_trait]
impl File for Fat32File {
    /// 用于表示可读。
    fn readable(&self) -> bool {
        self.readable
    }
    /// 用于表示可写。
    fn writable(&self) -> bool {
        self.writable
    }
    /// 返回文件的元数据的引用。
    fn metadata(&self) -> &FileMeta {
        self.meta.as_ref().expect("File metadata is not set")
    }
    /// 用于异步地从文件中读取数据到缓冲区中，并返回读取的字节数或错误。
    async fn read(&self, buf: &mut [u8]) -> Result<isize, SyscallErr> {
        let mut total_read_size = 0usize;
        let _sum_guard = SumGuard::new();
        let mut inner = self.inner.lock();

        let bytes = match &mut inner.node {
            Fat32NodeType::Dir() => panic!("Directories cannot be read as files"),
            Fat32NodeType::File(file) => file.read(buf),
        };

        total_read_size += bytes.expect("Failed to read file");
        inner.offset += total_read_size;

        Ok(total_read_size as isize)
    }
    /// 用于从文件中读取数据，同步。
    fn sync_read(&self, buf: &mut [u8]) -> Result<isize, SyscallErr> {
        let mut total_read_size = 0usize;
        let _sum_guard = SumGuard::new();
        let mut inner = self.inner.lock();

        let bytes = match &mut inner.node {
            Fat32NodeType::Dir() => panic!("Directories cannot be read as files"),
            Fat32NodeType::File(file) => {
                let res = file.read(buf);
                res
            }
        };

        total_read_size += bytes.expect("Failed to read file");
        inner.offset += total_read_size;

        Ok(total_read_size as isize)
    }
    /// 异步函数，用于向文件中写入数据。
    async fn write(&self, buf: &[u8]) -> Result<isize, SyscallErr> {
        let mut total_write_size = 0usize;
        let _sum_guard = SumGuard::new();
        let mut inner = self.inner.lock();

        let bytes = match &mut inner.node {
            Fat32NodeType::Dir() => panic!("Directories cannot be written as files"),
            Fat32NodeType::File(file) => {
                let res = file.write(buf);
                res
            }
        };

        total_write_size += bytes.expect("Failed to write to file");
        inner.offset += total_write_size;
        self.metadata()
            .inner
            .lock()
            .inode
            .as_ref()
            .expect("File inode is not set")
            .metadata()
            .inner
            .lock()
            .size += total_write_size;

        Ok(total_write_size as isize)
    }
    /// 同步函数，用于向文件中写入数据。
    fn sync_write(&self, buf: &[u8]) -> Result<isize, SyscallErr> {
        let mut total_write_size = 0usize;
        let _sum_guard = SumGuard::new();
        let mut inner = self.inner.lock();

        let bytes = match &mut inner.node {
            Fat32NodeType::Dir() => panic!("Directories cannot be written as files"),
            Fat32NodeType::File(file) => {
                let res = file.write(buf);
                res
            }
        };

        total_write_size += bytes.expect("Failed to write to file");
        inner.offset += total_write_size;
        self.metadata()
            .inner
            .lock()
            .inode
            .as_ref()
            .expect("File inode is not set")
            .metadata()
            .inner
            .lock()
            .size += total_write_size;

        Ok(total_write_size as isize)
    }
    /// 在文件中进行定位操作，如果文件类型是目录，则会抛出 panic，如果是文件类型，则使用 fatfs 库来实现具体的定位。
    fn seek(&self, offset: usize) -> Result<isize, SyscallErr> {
        let mut inner = self.inner.lock();
        match &mut inner.node {
            Fat32NodeType::Dir() => panic!("Directories cannot be seeked"),
            Fat32NodeType::File(file) => {
                if let Ok(pos) = file.seek(fatfs::SeekFrom::Start(offset as u64)) {
                    Ok(pos as isize)
                } else {
                    Err(SyscallErr::OtherError)
                }
            }
        }
    }
}

//! 此文件对fat32文件系统根节点进行操作。
//!
use crate::{
    fs::{
        fat32fs::{
            fat32fs::Fat32FileSystem,
            file::Fat32File,
            inode::{Fat32Inode, Fat32NodeType},
        },
        open_flags::OpenFlags,
        vfs::{
            file::{File, FileMeta, FileMetaInner},
            inode::{Inode, InodeMeta, InodeMode, INODE_CACHE},
        },
    },
    klib::error::SyscallErr,
};
use alloc::string::ToString;
use alloc::sync::Arc;
use spin::mutex::SpinMutex;

/// fat32根节点
pub struct Fat32RootInode {
    fs: &'static Fat32FileSystem,
    meta: Option<InodeMeta>,
}

impl Fat32RootInode {
    /// 创建了一个 Fat32RootInode 结构体的新实例，并将其返回。
    pub fn new(fs: &'static Fat32FileSystem, meta: Option<InodeMeta>) -> Self {
        Fat32RootInode { fs, meta }
    }
}

impl Inode for Fat32RootInode {
    /// 用于打开一个文件或目录。
    fn open(&self, this: Arc<dyn Inode>, flags: OpenFlags) -> Result<Arc<dyn File>, SyscallErr> {
        let (readable, writable) = flags.read_write();
        let file_meta_inner = FileMetaInner {
            inode: Some(this),
            pos: 0,
        };
        let file_meta = FileMeta {
            path: "/".to_string(),
            flags,
            inner: SpinMutex::new(file_meta_inner),
        };
        let fat32_file = Fat32File::new(Fat32NodeType::Dir(), Some(file_meta), readable, writable);
        Ok(Arc::new(fat32_file))
    }
    /// 获取节点元数据的方法，返回一个对 InodeMeta 类型的引用。
    fn metadata(&self) -> &InodeMeta {
        self.meta.as_ref().expect("Metadata not set")
    }
    /// 获取元数据，并使用 expect 方法在元数据不存在时抛出错误。
    fn set_metadata(&mut self, meta: InodeMeta) {
        self.meta = Some(meta);
    }
    /// 加载子节点的方法,遍历文件系统的根目录下的每个条目，并为每个条目创建一个 Fat32Inode 实例，然后将其存储在当前节点的子节点中。
    fn load_children(&self, this: Arc<dyn Inode>) {
        let mut meta_inner = self.meta.as_ref().expect("Metadata not set").inner.lock();
        for dentry in self.fs.fat_fs.root_dir().iter() {
            let dentry = dentry.expect("Failed to get dentry");
            let inode_mode = if dentry.is_dir() {
                InodeMode::FileDIR
            } else {
                InodeMode::FileREG
            };
            let file_name = dentry.file_name();
            let data_len = dentry.len();
            let meta = InodeMeta::new(
                Some(this.clone()),
                &file_name,
                inode_mode,
                data_len as usize,
            );
            let fat32_inode = Fat32Inode::new(dentry, Some(meta));
            meta_inner
                .children
                .insert(file_name.clone(), Arc::new(fat32_inode));
        }
    }
    /// 删除子节点的方法。
    fn delete_child(&self, child_name: &str) {
        let _ = self.fs.fat_fs.root_dir().remove(child_name);
    }
    /// 在文件系统中创建一个新的节点（文件或目录），并将其添加到相应的位置。
    fn mknod(
        &self,
        this: Arc<dyn Inode>,
        pathname: &str,
        mode: InodeMode,
        _dev_id: usize,
    ) -> Result<(), SyscallErr> {
        let name = pathname.to_string();
        let _ = self
            .fs
            .fat_fs
            .root_dir()
            .create_file(&name)
            .expect("Failed to create file");

        let new_dentry = self
            .fs
            .fat_fs
            .root_dir()
            .iter()
            .find(|dentry| dentry.as_ref().expect("Failed to get dentry").file_name() == name)
            .expect("Failed to find new dentry")
            .unwrap();

        let mut new_inode = Fat32Inode::new(new_dentry, None);
        new_inode.init(Some(this.clone()), pathname, mode, 0)?;

        let key = new_inode.metadata().inner.lock().hash_name.name_hash as usize;
        let new_inode_arc = Arc::new(new_inode);
        INODE_CACHE.lock().insert(key, new_inode_arc.clone());

        let mut this_meta_inner = this.metadata().inner.lock();
        this_meta_inner
            .children
            .insert(new_inode_arc.metadata().name.clone(), new_inode_arc);

        Ok(())
    }
    /// 在文件系统中创建一个新的目录，并将其添加到相应的位置。
    fn mkdir(
        &self,
        this: Arc<dyn Inode>,
        pathname: &str,
        mode: InodeMode,
    ) -> Result<(), SyscallErr> {
        let name = pathname.to_string();
        let _ = self
            .fs
            .fat_fs
            .root_dir()
            .create_dir(&name)
            .expect("Failed to create directory");

        let new_dentry = self
            .fs
            .fat_fs
            .root_dir()
            .iter()
            .find(|dentry| dentry.as_ref().expect("Failed to get dentry").file_name() == name)
            .expect("Failed to find new directory")
            .unwrap();

        let mut new_inode = Fat32Inode::new(new_dentry, None);
        new_inode.init(Some(this.clone()), pathname, mode, 0)?;

        let key = new_inode.metadata().inner.lock().hash_name.name_hash as usize;
        let new_inode_arc = Arc::new(new_inode);
        INODE_CACHE.lock().insert(key, new_inode_arc.clone());

        let mut this_meta_inner = this.metadata().inner.lock();
        this_meta_inner
            .children
            .insert(new_inode_arc.metadata().name.clone(), new_inode_arc);

        Ok(())
    }
}

//! 此文件用于初始化系统时初始化设备文件系统

use self::{block_device::BlockDeviceInode, zero::ZeroInode};
use super::vfs::file_system::{FileSystem, FILE_SYSTEM_MANAGER};
use crate::{
    fs::{
        devfs::devfs::{DevFs, DevWrapper},
        vfs::file_system::FileSystemType,
    },
    klib::error::SyscallErr,
};
use alloc::{string::ToString, sync::Arc};

pub mod block_device;
pub mod devfs;
pub mod inode;
pub mod null;
pub mod zero;

/// 创建一个设备文件系统实例，初始化其中的两个设备，然后将设备文件系统添加到文件系统管理器中。
/// 对设备管理器 (dev_mgr) 的设备映射 (dev_map) 进行了加锁，并调用了 insert 方法向映射中插入了两个键值对。
/// 对文件系统管理器 (FILE_SYSTEM_MANAGER) 的文件系统管理器 (fs_mgr) 进行了加锁，并调用了 insert 方法，向文件系统管理器中插入了一个键值对.
pub fn init() -> Result<(), SyscallErr> {
    let mut dev_fs = DevFs::new();
    dev_fs.init("/dev", FileSystemType::VFAT)?;

    let dev_fs = Arc::new(dev_fs);
    dev_fs.dev_mgr.dev_map.lock().insert(
        "vda2".to_string(),
        DevWrapper {
            dev_id: dev_fs
                .dev_mgr
                .id_allocator
                .fetch_add(1, core::sync::atomic::Ordering::AcqRel),
            inode: Arc::new(BlockDeviceInode::new()),
        },
    );
    dev_fs.dev_mgr.dev_map.lock().insert(
        "zero".to_string(),
        DevWrapper {
            dev_id: dev_fs
                .dev_mgr
                .id_allocator
                .fetch_add(1, core::sync::atomic::Ordering::AcqRel),
            inode: Arc::new(ZeroInode::new()),
        },
    );

    FILE_SYSTEM_MANAGER
        .fs_mgr
        .lock()
        .insert("/dev".to_string(), dev_fs);

    Ok(())
}

//! 此文件用以实现一个简单的设备文件系统 DevFs
