/// 设备文件系统
pub struct DevFs {
    pub metadata: Option<FileSystemMeta>,
    pub dev_mgr: Arc<DevManager>,
}

/// 设备管理器的结构体
pub struct DevManager {
    pub dev_map: SpinMutex<BTreeMap<String, DevWrapper>>,
    pub id_allocator: AtomicUsize,
}

/// 设备包装器的结构体
