impl FileSystem for DevFs {
    /// 用于在文件系统中创建根节点。
    fn create_root(
        &self,
        parent: Option<Arc<dyn Inode>>,
        mount_point: &str,
    ) -> Result<Arc<dyn Inode>, SyscallErr> {
        let mut root_inode = DevRootInode::new(self.dev_mgr.clone());
        root_inode.init(parent.clone(), mount_point, InodeMode::FileDIR, 0)?;
        let res = Arc::new(root_inode);
        // TODO: should we add a flag to indicate that this dentry(i.e dev) is no need to be flushed
        // to disk
        parent
            .expect("Need a parent")
            .metadata()
            .inner
            .lock()
            .children
            .insert(path_utils::get_name(mount_point).to_string(), res.clone());
        Ok(res)
    }
    /// 用于设置文件系统的元数据。
    fn set_metadata(&mut self, metadata: crate::fs::vfs::file_system::FileSystemMeta) {
        self.metadata = Some(metadata);
    }
