impl Inode for DevRootInode {
    /// 用于打开节点，并返回一个文件对象。
    fn open(&self, this: Arc<dyn Inode>, flags: OpenFlags) -> Result<Arc<dyn File>, SyscallErr> {
        Ok(Arc::new(DevRootDir {
            meta: FileMeta {
                path: self.metadata().path.clone(),
                flags,
                inner: SpinMutex::new(FileMetaInner {
                    inode: Some(this),
                    pos: 0,
                }),
            },
        }))
    }
