//! 这个文件实现了支持并发访问的管道机制
//! 是一种用于进程间通信（IPC）的机制
//！为 Pipe 实现文件管理相关方法.
//! 此文件思路来自titanix

use super::vfs::file::{File, FileMeta};
use crate::klib::error::SyscallErr;
use crate::task::smp::env::SumGuard;
use alloc::boxed::Box;
use alloc::sync::{Arc, Weak};
use async_trait::async_trait;
use log::debug;
use spin::mutex::SpinMutex;

/// 支持并发访问的管道
pub struct Pipe {
    readable: bool,
    writable: bool,

    // 管道使用的环形缓冲区，用于在管道的两端之间传递数据
    // 使用 Arc 和 SpinMutex 使得缓冲区可以在多个线程之间安全地共享和访问
    buffer: Arc<SpinMutex<PipeRingBuffer>>,
}

/// 为 Pipe 实现 File trait
#[async_trait]
impl File for Pipe {
    // 判断可读
    fn readable(&self) -> bool {
        self.readable
    }
    // 判断可写
    fn writable(&self) -> bool {
        self.writable
    }

    fn metadata(&self) -> &FileMeta {
        todo!()
    }
    /// 定义一个异步的read方法，从管道中读取数据到提供的缓冲区中
    async fn read(&self, buf: &mut [u8]) -> Result<isize, SyscallErr> {
        // 确保管道当前可读
        assert!(self.readable());

        let _sum_guard = SumGuard::new();
        // 想要从管道中读取的字节数
        let want_to_read = buf.len();
        // 将缓冲区转换为迭代器，以便逐个读取字节
        let mut buf_iter = buf.into_iter();

        // 已经读取的字节数
        let mut already_read = 0usize;

        // 循环读取数据，直到读取了所有请求的字节或管道关闭
        loop {
            // 调用内部处理函数来处理环形缓冲区的读取逻辑
            if let Some(ret) = self.inner_handler(|ring_buffer| {
                // 获取环形缓冲区当前可读的字节数
                let loop_read = ring_buffer.available_read();
                // 如果没有数据可读
                if loop_read == 0 {
                    if ring_buffer.all_write_ends_closed() {
                        // 则停止读取并返回已经读取的字节数
                        return Some(already_read);
                    }
                    // 否则，继续等待数据
                    return None;
                }

                // 循环读取环形缓冲区中的数据到缓冲区buf中
                for _ in 0..loop_read {
                    // 如果缓冲区buf还有空间
                    if let Some(byte_ref) = buf_iter.next() {
                        // 从环形缓冲区中读取一个字节
                        *byte_ref = ring_buffer.read_byte();

                        // 更新已经读取的字节数
                        already_read += 1;

                        // 如果已经读取了所有请求的字节
                        if already_read == want_to_read {
                            // 则停止读取并返回读取的字节数
                            return Some(want_to_read);
                        }
                    } else {
                        // 如果缓冲区buf没有空间了（这通常不应该发生，除非有错误）
                        // TODO: 处理错误或异常情况
                        // 这里简单返回已经读取的字节数作为错误处理
                        return Some(already_read);
                    }
                }

                // 如果环形缓冲区中还有数据但缓冲区buf已满，则等待下一次循环继续读取
                return None;
            }) {
                // 返回读取的字节数（转换为isize类型）
                return Ok(ret as isize);
            } else {
                // 如果没有数据可读，则让出当前任务，等待其他任务执行
                crate::task::thread::yield_now().await;
            }
        }
    }

    /// 定义一个异步函数write，它接收一个指向u8类型切片的引用buf，并返回一个Result，  
    /// 其中Ok包含一个isize类型的值（表示写入的字节数），Err包含一个SyscallErr类型的值（表示系统调用错误）。  
    async fn write(&self, buf: &[u8]) -> Result<isize, SyscallErr> {
        // 断言该对象（self）是可写的
        assert!(self.writable());

        // 调试输出，显示开始写入buf中的字节数
        debug!("start to pipe write {} bytes", buf.len());
        let _sum_guard = SumGuard::new();

        // 设定要写入的总字节数
        let want_to_write = buf.len();

        // 将buf转换为一个迭代器，以便逐个字节地处理
        let mut buf_iter = buf.into_iter();

        // 设定已经写入的字节数为0
        let mut already_write = 0usize;

        // 无限循环，直到所有数据都被写入或发生错误
        loop {
            // 调用self的inner_handler方法，该方法接受一个闭包，该闭包操作ring_buffer
            if let Some(ret) = self.inner_handler(|ring_buffer| {
                // 获取环形缓冲区中当前可写入的字节数
                let loop_write = ring_buffer.available_write();

                // 如果没有可写入的字节空间
                if loop_write == 0 {
                    // 立即返回None，表示当前没有可写入的字节空间
                    return None;
                }

                // 最多写入loop_write个字节
                for _ in 0..loop_write {
                    // 如果buf_iter中还有字节
                    if let Some(byte_ref) = buf_iter.next() {
                        // 将字节写入环形缓冲区
                        ring_buffer.write_byte(*byte_ref);
                        // 更新已经写入的字节数
                        already_write += 1;
                        // 如果已经写入了所有要写入的数据
                        if already_write == want_to_write {
                            // 立即返回Some(want_to_write)，表示写入完成
                            return Some(want_to_write);
                        }
                    // 如果buf_iter中没有更多字节了
                    } else {
                        // 立即返回Some(already_write)，表示已写入所有可用的数据
                        return Some(already_write);
                    }
                }

                // 如果没有更多要写入的数据或环形缓冲区已满，则返回None
                return None;
            }) {
                // 如果inner_handler返回了Some(ret)，表示有数据被写入
                debug!("pipe write {} bytes over", ret);
                // 返回一个Ok结果，其中包含写入的字节数（转换为isize类型）
                return Ok(ret as isize);
            } else {
                // 如果inner_handler返回了None，表示当前没有可写入的字节空间
                debug!("no available write slots");
                // 等待当前任务被其他任务替换
                crate::task::thread::yield_now().await;
            }
        }
    }
}

