    /// buffer参数是一个Arc<SpinMutex<PipeRingBuffer>>，表示线程安全的环形缓冲区引用  
    pub fn read_end_with_buffer(buffer: Arc<SpinMutex<PipeRingBuffer>>) -> Self {
        Self {
            readable: true,
            writable: false,
            // 设置环形缓冲区
            buffer,
        }
    }

    /// 具有写入权限和给定环形缓冲区的Pipe
    pub fn write_end_with_buffer(buffer: Arc<SpinMutex<PipeRingBuffer>>) -> Self {
        Self {
            readable: false,
            writable: true,
            // 设置环形缓冲区
            buffer,
        }
    }

    /// 一个内部方法，用于执行与环形缓冲区相关的操作  
    /// 它接受一个闭包f，该闭包接收一个&mut PipeRingBuffer参数并返回T类型的值  
    /// 该方法会锁定环形缓冲区，并在其上执行闭包f，然后返回f的结果  
    fn inner_handler<T>(&self, f: impl FnOnce(&mut PipeRingBuffer) -> T) -> T {
        // 使用SpinMutex的lock方法获取对环形缓冲区的互斥访问权限
        // lock方法会阻塞直到它获取到锁，并返回一个&mut PipeRingBuffer
        f(&mut self.buffer.lock())
    }
}

