//! 此文件用以对虚拟io设备device的block进行处理
//! 定义相对应结构体和trait
//! 对指定block进行读写操作，分配页，以及虚拟地址物理地址转地址功能。

use crate::{
    config::mm::{KERNEL_DIRECT_OFFSET, PAGE_SIZE},
    driver::block::BlockDevice,
    mm::{
        address::{PhysAddr, PhysPageNum, StepByOne, VirtAddr},
        address_space::kernel_space::KERNEL_SPACE,
        frame_allocator::{frame_alloc, frame_dealloc, FrameTracker},
    },
};
use alloc::vec::Vec;
use lazy_static::lazy_static;
use log::debug;
use spin::mutex::SpinMutex;
