#[allow(unused)]
// const VIRTIO0: usize = 0x10001000;
const VIRTIO0: usize = 0x10001000 + KERNEL_DIRECT_OFFSET * PAGE_SIZE;

/// 包含一个spinmutex,用于对 VirtIOBlk 实例进行同步访问。
pub struct VirtIOBlock(SpinMutex<VirtIOBlk<'static, VirtioHal>>);

lazy_static! {
    /// 用于存储帧追踪器。
    static ref QUEUE_FRAMES: SpinMutex<Vec<FrameTracker>> = SpinMutex::new(Vec::new());
}

impl BlockDevice for VirtIOBlock {
    /// 获取了 VirtIOBlk 的锁，然后调用 read_block 方法来读取指定块号的数据到提供的缓冲区 buf 中。
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        let mut locked_device = self.0.lock();
        if let Err(e) = locked_device.read_block(block_id, buf) {
            panic!(
                "Error when reading VirtIOBlk, block_id {}: {:?}",
                block_id, e
            );
        }
    }
    /// 获取了 VirtIOBlk 的锁，然后调用 write_block 方法来将提供的缓冲区 buf 中的数据写入到指定块号。
    fn write_block(&self, block_id: usize, buf: &[u8]) {
        self.0
            .lock()
            .write_block(block_id, buf)
            .expect("Error when writing VirtIOBlk");
    }
}

impl VirtIOBlock {
    #[allow(unused)]
    /// 用于创建 VirtIOBlock 实例。
    pub fn new() -> Self {
        unsafe {
            let kernel_space = KERNEL_SPACE
                .as_ref()
                .expect("KERNEL SPACE not initialized yet");
            let page_table = &kernel_space.page_table;
            let pa = page_table
                .get()
                .as_ref()
                .unwrap()
                .translate_va(VirtAddr::from(VIRTIO0))
                .expect("Failed to translate virtual address")
                .0;
            let header = &mut *(VIRTIO0 as *mut VirtIOHeader);
            let virtio_blk =
                VirtIOBlk::<VirtioHal>::new(header).expect("Failed to initialize VirtIOBlk");

            Self(SpinMutex::new(virtio_blk))
        }
    }
}

pub struct VirtioHal;

impl Hal for VirtioHal {
    /// 用于分配一定数量的连续物理页，并返回它们的物理地址。
    fn dma_alloc(pages: usize) -> usize {
        let mut ppn_base = PhysPageNum(0);

        // Lock the queue in advance to ensure a contiguous area
        let mut queue_frames_locked = QUEUE_FRAMES.lock();

        for i in 0..pages {
            let frame = frame_alloc().unwrap();
            if i == 0 {
                ppn_base = frame.ppn;
            }
            assert_eq!(frame.ppn.0, ppn_base.0 + i);
            queue_frames_locked.push(frame);
        }

        let pa: PhysAddr = ppn_base.into();
        pa.0
    }
    /// 用于释放分配的物理页。
    fn dma_dealloc(pa: usize, pages: usize) -> i32 {
        let pa = PhysAddr::from(pa);
        let mut ppn_base: PhysPageNum = pa.into();

        for _ in 0..pages {
            frame_dealloc(ppn_base);
            ppn_base.step();
        }

        0
    }
    /// 将物理地址转换为虚拟地址。
    fn phys_to_virt(addr: usize) -> usize {
        debug!("phy2virt: addr {:#x}", addr);
        addr
    }
    /// 用于将虚拟地址转换为物理地址。
    fn virt_to_phys(vaddr: usize) -> usize {
        unsafe {
            let kernel_space = KERNEL_SPACE
                .as_ref()
                .expect("KERNEL SPACE not initialized yet");
            let page_table = kernel_space.page_table.get();
            let translated_addr = page_table
                .as_ref()
                .unwrap()
                .translate_va(VirtAddr::from(vaddr))
                .unwrap();
            translated_addr.0
        }
    }
}

//! 此文件用于对缓冲区进行操作管理
//! 定义了结构体以及trait
//! 用于缓存设备的缓冲区操作
//! 此文件思路来自titanix

use crate::{driver::block::BlockDevice, klib::error::SyscallErr};
use alloc::{collections::LinkedList, sync::Arc};
use spin::mutex::SpinMutex;

const BUFFER_POOL_SIZE: usize = 16;

const BUFFER_SIZE: usize = 512;

/// 定义了一个名为BufferCache的trait，用于缓存设备的缓冲区操作。
pub trait BufferCache {
    /// 用于在给定块的给定偏移量处执行修改操作。    
    fn write_buffer_at<T>(
        &self,
        block_no: usize,
        offset: usize,
        f: impl FnOnce(&mut T),
    ) -> Result<(), SyscallErr>;

    /// 用于读取给定块的给定偏移量处的数据。
    fn read_buffer_at<T>(
        &self,
        block_no: usize,
        offset: usize,
        f: impl FnOnce(&T),
    ) -> Result<(), SyscallErr>;

    /// 用于同步（将数据写入到永久存储介质）给定块。
    fn sync_all_buffers(&self) -> Result<(), SyscallErr>;
}

pub struct Buffer {
    block_device: Arc<dyn BlockDevice>,
    block_no: usize,
    dirty: bool,
    data: [u8; BUFFER_SIZE],
}

impl Buffer {
    fn new(block_no: usize, block_device: Arc<dyn BlockDevice>) -> Self {
        let mut buffer = [0u8; BUFFER_SIZE];
        block_device.read_block(block_no, &mut buffer);

        Self {
            block_device,
            block_no,
            dirty: false,
            data: buffer,
        }
    }

    fn write_at<T, R>(&mut self, offset: usize, operation: impl FnOnce(&mut T) -> R) -> R {
        let size_of_t = core::mem::size_of::<T>();
        assert!(offset + size_of_t <= BUFFER_SIZE);

        self.dirty = true;

        let target_ptr = unsafe { &mut *((&mut self.data[offset] as *mut u8) as *mut T) };
        operation(target_ptr)
    }

    fn read_at<T, R>(&self, offset: usize, operation: impl FnOnce(&T) -> R) -> R {
        let size_of_t = core::mem::size_of::<T>();
        assert!(offset + size_of_t <= BUFFER_SIZE);

        let source_ptr = unsafe { &*((&self.data[offset] as *const u8) as *const T) };
        operation(source_ptr)
    }

    fn sync(&self) {
        if self.dirty {
            self.block_device.write_block(self.block_no, &self.data);
        }
    }
}

/// 基于LRU（Least Recently Used，最近最少使用）算法的缓存，用于管理数据块的缓存。
pub struct LruBufferCache {
    /// Mapping from block number to buffer
    /// TODO: Consider optimizing with techniques like RCU
    cache_list: SpinMutex<LinkedList<(usize, Arc<SpinMutex<Buffer>>)>>,
    /// TODO: Evaluate if the block device should have its own buffer cache
    device: Arc<dyn BlockDevice>,
}

impl BufferCache for LruBufferCache {
    /// 在指定的数据块号和偏移量处写入数据。
    fn write_buffer_at<T>(
        &self,
        block_no: usize,
        offset: usize,
        operation: impl FnOnce(&mut T),
    ) -> Result<(), SyscallErr> {
        let buffer = self.get_or_create_buffer(block_no);
        buffer
            .ok_or(SyscallErr::OtherError)?
            .lock()
            .write_at(offset, operation);
        Ok(())
    }
    /// 从指定的数据块号和偏移量处读取数据。
    fn read_buffer_at<T>(
        &self,
        block_no: usize,
        offset: usize,
        operation: impl FnOnce(&T),
    ) -> Result<(), SyscallErr> {
        let buffer = self.get_or_create_buffer(block_no);
        buffer
            .ok_or(SyscallErr::OtherError)?
            .lock()
            .read_at(offset, operation);
        Ok(())
    }

    /// 将所有缓存中的数据块内容同步到块设备中。
    fn sync_all_buffers(&self) -> Result<(), SyscallErr> {
        let list_lock = self.cache_list.lock();
        for buffer in list_lock.iter() {
            buffer.1.lock().sync();
        }
        Ok(())
    }
}

impl LruBufferCache {
    /// 基于LRU（最近最少使用）缓存算法的缓存实现,返回一个新的 LruBufferCache 实例。
    pub fn new(device: Arc<dyn BlockDevice>) -> Self {
        Self {
            cache_list: SpinMutex::new(LinkedList::new()),
            device,
        }
    }
    /// 用于获取或创建缓存中的缓冲区。它接受一个 block_no 参数，表示要获取或创建的缓冲区的块号，并返回一个 Arc<SpinMutex<Buffer>> 类型的 Option。
    fn get_or_create_buffer(&self, block_no: usize) -> Option<Arc<SpinMutex<Buffer>>> {
        // TODO: Implement a hash table for faster lookups
        let mut list_lock = self.cache_list.lock();
        if let Some((index, _)) = list_lock
            .iter()
            .enumerate()
            .find(|(_, buffer)| buffer.0 == block_no)
        {
            // Move the buffer to the front to mark it as recently used
            let buffer = list_lock.remove(index);
            list_lock.push_front(buffer);
        } else {
            // Cache miss handling
            if list_lock.len() == BUFFER_POOL_SIZE {
                // Buffer pool is full, apply LRU eviction
                let oldest_buffer = &list_lock.back().unwrap().1;
                if Arc::strong_count(oldest_buffer) != 1 {
                    // All buffers are currently in use, system must panic
                    panic!("Buffer pool exhausted");
                }
                let oldest_buffer_lock = oldest_buffer.lock();
                if oldest_buffer_lock.dirty {
                    oldest_buffer_lock.sync();
                }
                drop(oldest_buffer_lock);
                list_lock.pop_back();
            }
            list_lock.push_front((
                block_no,
                Arc::new(SpinMutex::new(Buffer::new(block_no, self.device.clone()))),
            ));
        }
        Some(list_lock.front().unwrap().1.clone())
    }
}

