//! 此文件对输入输出设备进行管理
//! 定义结构体和trait
//! 用于对输入输出设备操作，包含读写等操作。
//! 此文件思路来自titanix

use crate::{
    config::fs::BLOCK_SIZE,
    driver::block::{
        buffer_cache::{BufferCache, LruBufferCache},
        BlockDevice,
    },
};
use alloc::sync::Arc;
use fatfs::{IoBase, Read, Seek, SeekFrom, Write};

/// 定义一个用于表示输入输出设备的结构体。
pub struct IoDevice {
    buffer_pool: LruBufferCache,
    offset: usize,
}
/// 用于表示FAT32文件系统的偏移量。
const FAT32_OFFSET: usize = 0;

/// IoDevice 类型是线程安全的，可以安全地在多个线程之间共享。
unsafe impl Sync for IoDevice {}

/// 当前这里将错误类型定义为空元组 ()。
impl IoBase for IoDevice {
    type Error = ();
}

/// 创建一个用于处理输入输出的设备 IoDevice 结构体
impl IoDevice {
    pub fn new(block_device: Arc<dyn BlockDevice>) -> Self {
        IoDevice {
            buffer_pool: LruBufferCache::new(block_device),
            offset: FAT32_OFFSET,
        }
    }
}

/// 这段代码实现了从 IoDevice 设备中读取数据的逻辑，首先计算读取的起始位置和结束位置，然后逐个读取数据块，直到读取完成。
impl Read for IoDevice {
    fn read(&mut self, buf: &mut [u8]) -> Result<usize, Self::Error> {
        let mut current_pos = self.offset;
        let max_pos = self.offset + buf.len();
        if current_pos >= max_pos {
            return Err(());
        }
        let mut block_num = current_pos / BLOCK_SIZE;
        let mut total_read_bytes = 0usize;

        while current_pos < max_pos {
            let next_block_boundary = (current_pos / BLOCK_SIZE + 1) * BLOCK_SIZE;
            let read_limit = next_block_boundary.min(max_pos);
            let read_amount = read_limit - current_pos;
            let destination_slice = &mut buf[total_read_bytes..total_read_bytes + read_amount];

            if self
                .buffer_pool
                .read_buffer_at(block_num, 0, |data_block: &[u8; BLOCK_SIZE]| {
                    let source_slice = &data_block
                        [current_pos % BLOCK_SIZE..current_pos % BLOCK_SIZE + read_amount];
                    destination_slice.copy_from_slice(source_slice);
                })
                .is_err()
            {
                self.offset += total_read_bytes;
                return Ok(total_read_bytes);
            }

            total_read_bytes += read_amount;
            current_pos = read_limit;
            block_num += 1;
        }
        self.offset += total_read_bytes;
        Ok(total_read_bytes)
    }
}
/// 实现了对块设备的高效写入操作，它会将数据分块写入到缓冲区中，以提高写入性能。
impl Write for IoDevice {
    fn write(&mut self, buf: &[u8]) -> Result<usize, Self::Error> {
        let mut current_pos = self.offset;
        let max_pos = self.offset + buf.len();
        assert!(current_pos <= max_pos);
        let mut block_num = current_pos / BLOCK_SIZE;
        let mut total_written_bytes = 0usize;

        while current_pos < max_pos {
            let next_block_boundary = (current_pos / BLOCK_SIZE + 1) * BLOCK_SIZE;
            let write_limit = next_block_boundary.min(max_pos);
            let write_amount = write_limit - current_pos;

            if self
                .buffer_pool
                .write_buffer_at(block_num, 0, |data_block: &mut [u8; BLOCK_SIZE]| {
                    let source_slice =
                        &buf[total_written_bytes..total_written_bytes + write_amount];
                    let destination_slice = &mut data_block
                        [current_pos % BLOCK_SIZE..current_pos % BLOCK_SIZE + write_amount];
                    destination_slice.copy_from_slice(source_slice);
                })
                .is_err()
            {
                self.offset += total_written_bytes;
                return Ok(total_written_bytes);
            }

            total_written_bytes += write_amount;
            current_pos = write_limit;
            block_num += 1;
        }
        Ok(total_written_bytes)
    }

    /// 将IoDevice中的所有缓冲区数据同步到底层的持久化存储介质中。
    fn flush(&mut self) -> Result<(), Self::Error> {
        self.buffer_pool.sync_all_buffers().map_err(|_| ())
    }
}

/// 对设备的定位操作，允许根据指定的偏移量相对于当前位置、文件末尾或者文件起始位置进行定位。
impl Seek for IoDevice {
    fn seek(&mut self, pos: SeekFrom) -> Result<u64, Self::Error> {
        match pos {
            SeekFrom::Current(offset) => {
                if offset < 0 {
                    self.offset = self.offset.saturating_sub(-offset as usize);
                } else {
                    self.offset = self.offset.saturating_add(offset as usize);
                }
            }
            SeekFrom::End(_) => {
                todo!()
            }
            SeekFrom::Start(offset) => {
                self.offset = FAT32_OFFSET + offset as usize;
            }
        }
        Ok(self.offset as u64)
    }
}

