use crate::config::others::RADIX_TREE_MAP_SHIFT;
use alloc::{sync::Arc, vec, vec::Vec};
use log::debug;
use spin::mutex::SpinMutex;

struct RadixTreeLeafNode<T: Clone> {
    key: usize,
    data: T,
}

struct RadixTreeInternalNode<T: Clone> {
    children: SpinMutex<[Option<RadixTreeNode<T>>; 2 << RADIX_TREE_MAP_SHIFT]>,
}

impl<T: Clone> RadixTreeInternalNode<T> {
    pub fn new() -> Self {
        Self {
            children: SpinMutex::new(core::array::from_fn(|_| None)),
        }
    }
}

enum RadixTreeNode<T: Clone> {
    // TODO: not sure use `Box` or `Mutex` or something like that
    InternalNode(Arc<RadixTreeInternalNode<T>>),
    LeafNode(RadixTreeLeafNode<T>),
}

/// To simplify, this struct only fits for those whose Key type is `usize`
pub struct RadixTree<T: Clone> {
    level_num: usize,
    root: Arc<RadixTreeInternalNode<T>>,
}

// TODO: implement iterator for RadixTree<T>

impl<T: Clone> RadixTree<T> {
    pub fn new(level_num: usize) -> Self {
        Self {
            level_num,
            root: Arc::new(RadixTreeInternalNode::new()),
        }
    }
    /// Lookup the give key.
    /// Note that elements that have the same low bits will be put into
    /// the same slot. This is what we want because when this structure
    /// is applied in `PageCache`, we will read pages contiguously.
    pub fn lookup(&self, key: usize) -> Option<T> {
        let indice = self.indice(key);
        let mut parent = self.root.clone();
        for index in indice {
            let children = parent.children.lock();
            if let Some(node) = children[index].as_ref() {
                match node {
                    RadixTreeNode::InternalNode(node) => {
                        let node = node.clone();
                        drop(children);
                        parent = node;
                    }
                    RadixTreeNode::LeafNode(node) => {
                        if node.key != key {
                            return None;
                        } else {
                            return Some(node.data.clone());
                        }
                    }
                }
            } else {
                return None;
            }
        }
        return None;
    }

    pub fn insert(&mut self, key: usize, value: T) {
        let indice = self.indice(key);
        let mut parent = self.root.clone();
        for (i, index) in indice.iter().enumerate() {
            let mut children = parent.children.lock();
            if children[*index].is_none() {
                if i == indice.len() - 1 {
                    debug!("[Radix tree]: insert a new leaf, key: {:#x}", key);
                    children[*index] = Some(RadixTreeNode::LeafNode(RadixTreeLeafNode {
                        key,
                        data: value,
                    }));
                    return;
                }
                children[*index] = Some(RadixTreeNode::InternalNode(Arc::new(
                    RadixTreeInternalNode::new(),
                )));
            }
            let node = children[*index].as_ref().unwrap();
            match node {
                RadixTreeNode::InternalNode(node) => {
                    let node = node.clone();
                    drop(children);
                    parent = node;
                }
                RadixTreeNode::LeafNode(_) => {
                    debug!(
                        "[Radix tree]: replace old leaf with a new one, key: {:#x}",
                        key
                    );
                    children[*index] = Some(RadixTreeNode::LeafNode(RadixTreeLeafNode {
                        key,
                        data: value,
                    }));
                    return;
                }
            }
        }
    }

    fn indice(&self, mut key: usize) -> Vec<usize> {
        let mut indice = vec![0usize; self.level_num];
        for i in (0..self.level_num).rev() {
            indice[i] = key & ((1 << RADIX_TREE_MAP_SHIFT) - 1);
            key >>= RADIX_TREE_MAP_SHIFT;
        }
        indice
    }
}

use alloc::{string::String, vec, vec::Vec};

pub trait Hashable {
    fn hash(&self) -> usize;
}

impl Hashable for String {
    // http://www.cse.yorku.ca/~oz/hash.html
    fn hash(&self) -> usize {
        let mut result: usize = 5381;
        for c in self.bytes() {
            result = ((result << 5).wrapping_add(result)).wrapping_add(c.into());
        }
        result
    }
}

impl Hashable for usize {
    fn hash(&self) -> usize {
        *self
    }
}

#[derive(Clone)]
struct HashCell<Key, Value> {
    key: Key,
    value: Option<Value>,
}

pub struct HashTable<Key, Value> {
    cells: Vec<HashCell<Key, Value>>,
    taken_count: usize,
}

impl<Key, Value> HashTable<Key, Value>
where
    Key: Clone + Default + PartialEq + Hashable,
    Value: Clone,
{
    pub fn new() -> Self {
        const INITIAL_CAPACITY: usize = 13;
        let ret = Self {
            // cells: Vec::with_capacity(INITIAL_CAPACITY),
            cells: vec![
                HashCell {
                    key: Key::default(),
                    value: None,
                };
                INITIAL_CAPACITY
            ],
            taken_count: 0,
        };
        // debug!("hash table capacity {}", ret.cells.len());
        ret
    }

    pub fn extend(&mut self) {
        assert!(self.cells.len() > 0);
        let mut new_self = Self {
            cells: Vec::with_capacity(self.cells.len() * 2 + 1),
            taken_count: 0,
        };

        for cell in self.cells.iter() {
            if cell.value.is_some() {
                new_self.insert(cell.key.clone(), cell.value.clone().unwrap());
            }
        }

        *self = new_self;
    }

    pub fn insert(&mut self, key: Key, new_value: Value) {
        if let Some(old_value) = self.get_mut(&key) {
            *old_value = new_value;
        } else {
            if self.taken_count >= self.cells.len() {
                self.extend();
            }
            assert!(self.taken_count < self.cells.len());

            let mut index = key.hash() % self.cells.len();

            while self.cells[index].value.is_some() {
                index = (index + 1) % self.cells.len();
            }

            self.cells[index].key = key;
            self.cells[index].value = Some(new_value);
            self.taken_count += 1;
        }
    }

    pub fn delete(&mut self, key: Key) {
        if let Some(index) = self.get_index(&key) {
            self.cells[index].value.take();
        }
    }

    fn get_index(&self, key: &Key) -> Option<usize> {
        let mut index = key.hash() % self.cells.len();
        for _ in 0..self.cells.len() {
            if !self.cells[index].value.is_some() {
                break;
            }

            if self.cells[index].key == *key {
                break;
            }

            index = (index + 1) % self.cells.len();
        }

        if self.cells[index].value.is_some() && self.cells[index].key == *key {
            Some(index)
        } else {
            None
        }
    }

    #[allow(dead_code)]
    pub fn get(&self, key: &Key) -> Option<&Value> {
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_ref()
            // Some(&self.cells[index].value)
        } else {
            None
        }
    }

    pub fn get_mut(&mut self, key: &Key) -> Option<&mut Value> {
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_mut()
            // Some(&mut self.cells[index].value)
        } else {
            None
        }
    }
}

use alloc::vec::Vec;

/// Used for allocating pid & tid
pub struct RecycleAllocator {
    current: usize,
    recycled: Vec<usize>,
}

impl RecycleAllocator {
    ///Create an empty `RecycleAllocator`
    pub fn new() -> Self {
        RecycleAllocator {
            current: 0,
            // TODO: use heap to replace vec
            recycled: Vec::new(),
        }
    }
    ///Allocate an id
    pub fn alloc(&mut self) -> usize {
        if let Some(id) = self.recycled.pop() {
            id
        } else {
            self.current += 1;
            self.current - 1
        }
    }
    ///Recycle an id
    pub fn dealloc(&mut self, id: usize) {
        assert!(id < self.current);
        assert!(
            !self.recycled.iter().any(|iid| *iid == id),
            "id {} has been deallocated!",
            id
        );
        self.recycled.push(id);
    }
}

use crate::{
    config::{mm::PAGE_SIZE, others::SYSCALL_STR_ARG_MAX_LEN},
    mm::address::VirtAddr,
    task::{smp::{current_process, env::SumGuard}, thread::exit::exit_and_terminate_all_threads},
    trap::trap_handler::set_user_trap_entry,
};
use core::arch::global_asm;
use log::{debug, error};
use riscv::register::{stvec, utvec::TrapMode};

use super::error::SyscallErr;

global_asm!(include_str!("check.S"));
///
pub struct UserCheck {
    _sum_guard: SumGuard,
}

extern "C" {
    fn __try_access_user_error_trap();
    fn __try_read_user_u8(user_addr: usize) -> (usize, usize);
    fn __try_write_user_u8(user_addr: usize) -> (usize, usize);
    fn __alltraps();
}

impl Drop for UserCheck {
    fn drop(&mut self) {
        unsafe {
            stvec::write(set_user_trap_entry as usize, TrapMode::Direct);
        }
    }
}
impl UserCheck {
    /// Create a new UserCheck
    pub fn new() -> Self {
        unsafe {
            stvec::write(__try_access_user_error_trap as usize, TrapMode::Direct);
        }
        let ret = Self {
            _sum_guard: SumGuard::new(),
        };
        ret
    }

    /// Check wether the given user addr is readable or not
    pub fn check_readable_slice(&self, buf: *const u8, len: usize) -> Result<(), SyscallErr> {
        // let _sum_guard = SumGuard::new();
        let buf_start: VirtAddr = VirtAddr::from(buf as usize).floor().into();
        let buf_end: VirtAddr = VirtAddr::from(buf as usize + len).ceil().into();
        let mut va = buf_start;
        // debug!("[proc {}] check read sva {:#x} eva {:#x}", current_process().pid(), buf_start.0, buf_end.0);
        while va < buf_end {
            if let Some(scause) = self.try_read_u8(va.into()) {
                self.handle_page_fault(&mut va, scause)?;
            }
            va.0 += PAGE_SIZE;
        }
        Ok(())
    }

    /// Check wether the given user addr is writable or not
    pub fn check_writable_slice(&self, buf: *mut u8, len: usize) -> Result<(), SyscallErr> {
        // let _sum_guard = SumGuard::new();
        let buf_start: VirtAddr = VirtAddr::from(buf as usize).floor().into();
        let buf_end: VirtAddr = VirtAddr::from(buf as usize + len).ceil().into();
        let mut va = buf_start;
        while va < buf_end {
            if let Some(scause) = self.try_write_u8(va.into()) {
                self.handle_page_fault(&mut va, scause)?
            }
            va.0 += PAGE_SIZE;
        }
        Ok(())
    }

    /// Check wether the given user c string is legal or not.
    pub fn check_c_str(&self, c_str: *const u8) -> Result<(), SyscallErr> {
        debug!("[kernel] check c str");
        let start_addr: VirtAddr = VirtAddr::from(c_str as usize).floor().into();
        let mut va = start_addr;
        let mut first = true;
        loop {
            if let Some(scause) = self.try_read_u8(va.into()) {
                self.handle_page_fault(&mut va, scause)?
            }
            if first {
                if self.check_c_str_end(VirtAddr::from(c_str as usize)) {
                    return Ok(());
                }
            } else {
                if self.check_c_str_end(va) {
                    return Ok(());
                }
            }
            va.0 += PAGE_SIZE;
            if va.0 - VirtAddr::from(c_str as usize).0 >= SYSCALL_STR_ARG_MAX_LEN {
                error!(
                    "user c str too long!, first {}, va {:#x}, str {:#x}",
                    first, va.0, c_str as usize
                );
                return Err(SyscallErr::OtherError);
            }
            if first {
                first = false;
            }
        }
    }

    fn check_c_str_end(&self, va: VirtAddr) -> bool {
        let end: VirtAddr = VirtAddr::from(VirtAddr::from(va.floor()).0 + PAGE_SIZE);
        for addr in va.0..end.0 {
            let ch: u8 = unsafe { *(addr as *const u8) };
            if ch == 0 {
                return true;
            }
        }
        false
    }

    /// return `scause` if page fault
    fn try_read_u8(&self, user_addr: usize) -> Option<usize> {
        // debug!("satp(2) {:#x}", satp::read().bits());
        // debug!("try read u8, addr {:#x}", user_addr);
        let (a0, scause) = unsafe { __try_read_user_u8(user_addr) };
        match a0 {
            0 => None,
            _ => Some(scause),
        }
    }

    fn try_write_u8(&self, user_addr: usize) -> Option<usize> {
        let (a0, _scause) = unsafe { __try_write_user_u8(user_addr) };
        match a0 {
            0 => None,
            // TODO: optimize
            _ => Some(15),
        }
    }

    fn handle_page_fault(&self, va: &mut VirtAddr, scause: usize) -> Result<(), SyscallErr> {
        match current_process().inner_handler(|proc| proc.memory_set.handle_page_fault(*va, scause))
        {
            Ok(()) => {
                debug!(
                    "[kernel] [proc {}]handle legal page fault, addr {:#x}",
                    current_process().pid(),
                    va.0
                );
                va.0 += PAGE_SIZE;
                Ok(())
            }
            Err(_) => {
                error!(
                    "[kernel] [user check](scause:{}) in application, bad addr = {:#x}, kernel killed it. pid: {}",
                    scause,
                    va.0,
                    current_process().pid()
                );
                exit_and_terminate_all_threads(-2);
                // current_process().inner_handler(|proc| {
                //     proc.exit_code = -2;
                //     proc.is_zombie = true;
                // });
                return Err(SyscallErr::OtherError);
            }
        }
    }
}

use super::string_converter::c_str_to_string;
use crate::task::smp::current_process;
use alloc::{
    string::{String, ToString},
    vec::Vec,
};
use log::debug;

pub fn path2vec(path_name: &str) -> Vec<&str> {
    path_name.split('/').filter(|name| *name != "").collect()
}

pub fn get_name(path_name: &str) -> &str {
    let dentry_vec: Vec<&str> = path_name.split('/').collect();
    dentry_vec[dentry_vec.len() - 1]
}

pub fn judge_is_relative(path: &str) -> bool {
    if path.starts_with("/") {
        return false;
    } else {
        return true;
    }
}

pub fn change_relative_to_absolute(relative_path: &str, cwd: &str) -> Option<String> {
    let absolute_path_vec = path2vec(cwd);
    let relative_path_vec = path2vec(relative_path);
    debug!("absolute path: {:?}", absolute_path_vec);
    debug!("relative path: {:?}", relative_path_vec);
    let mut res: Vec<&str> = Vec::new();
    if absolute_path_vec.len() == 0 {
        res.push("");
    } else {
        for i in 0..absolute_path_vec.len() {
            res.push(absolute_path_vec[i]);
        }
    }
    for i in 0..relative_path_vec.len() {
        match relative_path_vec[i] {
            ".." => {
                if let Some(check) = res.pop() {
                    if check == "" {
                        return None;
                    }
                }
            }
            "." => {}
            _ => {
                res.push(relative_path_vec[i]);
            }
        }
    }
    Some(res.join("/"))
}

pub fn path_process(path: *const u8) -> Option<String> {
    let path = &c_str_to_string(path);
    debug!("path name {}", path);
    let absolute_path;
    if judge_is_relative(path) {
        debug!("It is a relative path");
        let cwd = current_process().inner_handler(move |proc| proc.cwd.clone());
        absolute_path = change_relative_to_absolute(path, &cwd);
    } else {
        debug!("It is a absolute path");
        absolute_path = Some(path.clone());
    }
    absolute_path
}

pub fn path_with_dirfd(dirfd: isize, path: *const u8) -> Option<String> {
    let path = &c_str_to_string(path);
    debug!("path name {}", path);
    let absolute_path: Option<String>;
    if judge_is_relative(path) {
        absolute_path = current_process().inner_handler(|proc| {
            let wd_inode = proc.fd_table.get_ref(dirfd as usize);
            match wd_inode {
                Some(wd_inode) => {
                    let wd = wd_inode.metadata().path.clone();
                    change_relative_to_absolute(path, &wd)
                }
                None => None,
            }
        });
    } else {
        absolute_path = Some(path.clone());
    }
    absolute_path
}

pub fn get_parent_dir(path_name: &str) -> Option<String> {
    let dentry_vec: Vec<&str> = path2vec(path_name);
    debug!("dentry vec {:?}", dentry_vec);
    if dentry_vec.is_empty() {
        return None;
    }
    let mut res = "".to_string();
    for i in 0..dentry_vec.len() - 1 {
        res += "/";
        res += dentry_vec[i];
    }
    if res == "" {
        res += "/";
    }
    Some(res)
}

