//! 时间管理相关系统调用
//! 包括获取当前时间、使当前线程休眠指定时间

use crate::{klib::{error::SyscallErr, user_check::UserCheck}, task::{smp::env::SumGuard, thread}, timer::get_time_ms};

pub struct TimeVal {
    sec: usize,
    usec: usize,
}

pub struct TimeSpec {
    sec: usize,
    nsec: usize,
}


pub struct Tms {
    utime: usize,
    stime: usize,
    cutime: usize,
    cstime: usize,
}

pub fn sys_times(buf: *mut Tms) -> Result<isize, SyscallErr> {
    // 检查指针指向的内存是否可写，并且大小符合要求
    UserCheck::new().check_writable_slice(buf as *mut u8, core::mem::size_of::<Tms>())?;

    // 创建 SumGuard 实例，用于某些操作
    let _sum_guard = SumGuard::new();

    // 将 buf 转换为可变引用以修改其值
    let tms = unsafe { &mut *buf };

    // 修改 Tms 结构体的各字段值
    tms.stime = 114514;
    tms.utime = 114514;
    tms.cstime = 114514;
    tms.cutime = 114514;

    // 返回成功状态
    Ok(0)
}

// 系统调用：获取当前时间
pub fn sys_gettimeofday(time_val_ptr: *mut TimeVal) -> Result<isize, SyscallErr> {
    // 检查指针指向的内存是否可写，并且大小符合要求
    UserCheck::new().check_writable_slice(time_val_ptr as *mut u8, core::mem::size_of::<TimeVal>())?;

    // 创建 SumGuard 实例，用于某些操作
    let _sum_guard = SumGuard::new();

    // 获取当前时间（毫秒）
    let current_time = get_time_ms();

    // 构建 TimeVal 结构体
    let time_val = TimeVal {
        sec: current_time / 1000,
        usec: current_time % 1000 * 1000,
    };

    // 将 TimeVal 结构体写入指针指向的内存
    unsafe {
        time_val_ptr.write_volatile(time_val);
    }

    // 返回成功状态
    Ok(0)
}


/// 使当前线程休眠指定的纳秒。
///
/// # 参数
///
/// * `time_val_ptr` - 指向包含休眠时间的 `TimeSpec` 结构体的指针。
///
/// # 返回值
/// 
/// 返回 0
pub async fn sys_nanosleep(time_val_ptr: usize) -> Result<isize, SyscallErr> {
    // 计算需要休眠的毫秒数
    let sleep_ms = {
        // 检查传入的指针是否指向可读的 `TimeVal` 结构体
        UserCheck::new()
            .check_readable_slice(time_val_ptr as *const u8, core::mem::size_of::<TimeVal>())?;

        // 创建 SumGuard 实例，用于保护和管理资源
        let _sum_guard = SumGuard::new();

        // 将 usize 类型的指针转换为 `TimeSpec` 类型的指针
        let time_val_ptr = time_val_ptr as *const TimeSpec;
        // 安全地访问指针指向的数据
        let time_val = unsafe { &(*time_val_ptr) };
        // 将秒和纳秒转换为毫秒
        time_val.sec * 1000 + time_val.nsec / 1000000
    };

    // 获取休眠开始时的毫秒时间戳
    let start_ms = get_time_ms();
    // 计算休眠结束的目标毫秒时间戳
    let end_ms = sleep_ms + start_ms;

    // 循环检查当前时间，以确定是否到达了休眠结束时间
    loop {
        let now_ms = get_time_ms();
        // 如果当前时间大于或等于结束时间，则结束休眠
        if now_ms >= end_ms {
            return Ok(0);
        }
        // 当前线程让出 CPU 时间片，等待下一次调度
        thread::yield_now().await;
    }
}

