/// 标准输入流结构体
pub struct Stdin;

/// 标注输出流结构体
pub struct Stdout;

/// 为 Stdin 实现 File trait
#[async_trait]
impl File for Stdin {
    /// Stdin 是可读的
    fn readable(&self) -> bool {
        true
    }

    /// Stdin 是不可写的
    fn writable(&self) -> bool {
        false
    }

    /// 获取流的元数据 尚未实现
    /// 而对于 Stdin 来说，可能并不总是能提供完整的元数据集需要考虑
    fn metadata(&self) -> &FileMeta {
        todo!()
    }

    /// 异步读取函数，读取一个字符将其存在缓存区buf中
    async fn read(&self, buf: &mut [u8]) -> Result<isize, SyscallErr> {
        // 确保传入的缓冲区buf的长度为1
        assert_eq!(buf.len(), 1, "Only support len = 1 in sys_read!");
        let mut c: usize;
        loop {
            // 从控制台读取一个字符
            c = console_getchar();
            // 让当前线程让步的函数，允许其他任务或线程运行 await关键字等待这个异步操作完成
            crate::task::thread::yield_now().await;
            // 为空字符继续
            if c == 0 {
                continue;
            } else {
                break;
            }
        }
        // 转化为 char 并写入buf
        let ch = c as u8;
        let _sum_guard = SumGuard::new();
        buf[0] = ch;
        // 返回一个Ok(1)，表明成功地写入了1个字节
        Ok(1)
    }
    /// 表明不可写 并返回错误结果
    async fn write(&self, _: &[u8]) -> Result<isize, SyscallErr> {
        warn!("Cannot write to stdin");
        Err(SyscallErr::OtherError)
    }
}

/// 为 Stdout 类型实现 File trait
#[async_trait]
impl File for Stdout {
    /// 不可读
    fn readable(&self) -> bool {
        false
    }

    /// 可写
    fn writable(&self) -> bool {
        true
    }

    /// 获取 Stdout 元数据
    fn metadata(&self) -> &FileMeta {
        todo!()
    }

    /// 表明 Stdout 不可读
    async fn read(&self, _: &mut [u8]) -> Result<isize, SyscallErr> {
        warn!("Cannot read stdout");
        Err(SyscallErr::OtherError)
    }

    /// 写出结果
    async fn write(&self, buf: &[u8]) -> Result<isize, SyscallErr> {
        let _sum_guard = SumGuard::new();
        // 将 buf 转换为UTF-8字符串 根据结果打印
        print!("{}", core::str::from_utf8(buf).unwrap());
        // 返回写入的字节数
        Ok(buf.len() as isize)
    }
}

//！ 您定义了一个名为HashName的结构体，封装一个名称的哈希值、其父级索引以及名称本身
//！ 自定义的哈希器，以及计算方式
//！ 用该数据结构提高文件搜索效率
//! 此文件思路来自titanix

use crate::klib::collections::hash_table::Hashable;
use alloc::sync::Arc;
use core::hash::{BuildHasher, BuildHasherDefault, Hasher};

/// 定义HashName结构体，它包含名称的哈希值、父级索引和名称本身  
#[derive(Clone, PartialEq)]
pub struct HashName {
    pub name_hash: u64, // 名称的哈希值
    pub parent: usize,  // 父级索引
    pub name: Arc<str>, // 名称，以Arc<str>形式存储以便共享
}

/// 定义MyHasher结构体，它包装了一个u64用于存储哈希过程中的中间值  
#[derive(Default)]
struct MyHasher(u64);

/// 为MyHasher实现Hasher trait，定义如何计算哈希值  
impl Hasher for MyHasher {
    fn write(&mut self, bytes: &[u8]) {
        // 定义两个常量用于哈希计算
        const MUL: u64 = 130923192384972381;
        const ADD: u64 = 410934879347345269;
        // 遍历字节并使用给定的常数进行哈希计算
        self.0 = bytes.iter().fold(self.0, |acc, &b| {
            acc.wrapping_add((b as u64).wrapping_mul(MUL))
                .wrapping_add(ADD)
        });
    }

    fn finish(&self) -> u64 {
        // 返回最终的哈希值
        self.0
    }
}

/// 为HashName类型实现一些方法  
impl HashName {
    /// 将字符串转换为哈希值  
    pub fn str2num(name: &str) -> u64 {
        // 使用BuildHasherDefault和MyHasher创建一个哈希器，并使用它哈希字符串
        let hasher = BuildHasherDefault::<MyHasher>::default();
        hasher.hash_one(name)
    }

    /// 使用基础哈希值和名称哈希值进行自定义哈希组合  
    pub fn myhash(base: u64, name: u64) -> u64 {
        base.rotate_left(32).wrapping_add(name)
    }

    /// 创建一个新的HashName实例
    pub fn hash_name(parent: Option<usize>, name: &str) -> Self {
        // 将Option<usize>转换为u64（如果为None，则使用0）
        let parent_ptr = parent.unwrap_or(0) as u64;
        // 计算name的哈希值
        let name_hash = Self::myhash(parent_ptr, Self::str2num(name));
        // 创建一个新的HashName实例
        HashName {
            name_hash,
            parent: parent_ptr as usize,
            name: Arc::from(name),
        }
    }
}

/// 为HashName实现Hashable trait
impl Hashable for HashName {
    // 返回HashName实例的哈希值
    // 注意：这里假设HashName已经被正确地哈希 即，name_hash字段已经包含有效的哈希值
    fn hash(&self) -> usize {
        self.name_hash as usize
    }
}

//! 该文件用于文件描述符表的相关操作

use super::{
    stdio::{Stdin, Stdout},
    vfs::file::File,
};
use alloc::{sync::Arc, vec, vec::Vec};

pub struct FileDescriptorTable {
    fd_table: Vec<Option<Arc<dyn File>>>,
}

impl FileDescriptorTable {
    pub fn new() -> Self {
        // 初始化文件描述符表
        let initial_fds: Vec<Option<Arc<dyn File>>> = vec![
            // 标准输入 (stdin) -> 文件描述符 0
            Some(Arc::new(Stdin)),
            // 标准输出 (stdout) -> 文件描述符 1
            Some(Arc::new(Stdout)),
            // 标准错误 (stderr) -> 文件描述符 2
            Some(Arc::new(Stdout)),
        ];
        Self {
            fd_table: initial_fds,
        }
    }

    pub fn from_another(fd_table: &FileDescriptorTable) -> Self {
        // 从另一个文件描述符表复制
        let mut new_table = Vec::with_capacity(fd_table.fd_table.len());
        for fd in &fd_table.fd_table {
            new_table.push(fd.as_ref().cloned());
        }
        Self { fd_table: new_table }
    }

    /// 获取指定文件描述符的引用
    pub fn get_ref(&self, fd: usize) -> Option<&Arc<dyn File>> {
        // 检查文件描述符是否超出范围
        self.fd_table.get(fd)?.as_ref()
    }

    /// 通过克隆获取指定文件描述符的所有权
    pub fn get(&self, fd: usize) -> Option<Arc<dyn File>> {
        // 获取文件描述符对应的文件
        self.fd_table.get(fd)?.clone()
    }

    /// 获取指定文件描述符的所有权并将其从表中移除
    pub fn take(&mut self, fd: usize) -> Option<Arc<dyn File>> {
        // 检查文件描述符是否超出范围并移除
        self.fd_table.get_mut(fd)?.take()
    }

    /// 将文件插入到指定文件描述符位置
    pub fn put(&mut self, fd: usize, file: Arc<dyn File>) {
        assert!(fd < self.fd_table.len(), "文件描述符超出范围");
        assert!(self.fd_table[fd].is_none(), "文件描述符已被使用");
        self.fd_table[fd] = Some(file);
    }

    /// 分配一个新的文件描述符
    pub fn alloc_fd(&mut self) -> usize {
        // 尝试找到一个空闲槽位，否则扩展表
        if let Some(fd) = self.free_slot() {
            fd
        } else {
            self.fd_table.push(None);
            self.fd_table.len() - 1
        }
    }

    /// 分配指定的文件描述符
    pub fn alloc_spec_fd(&mut self, newfd: usize) -> usize {
        if newfd >= self.fd_table.len() {
            self.fd_table.resize(newfd + 1, None);
        }
        newfd
    }

    /// 找到一个空闲的文件描述符槽位
    fn free_slot(&self) -> Option<usize> {
        self.fd_table.iter().position(Option::is_none)
    }
}

use crate::mm::address_space::memory_map::MapPermission;  
use bitflags::bitflags;  

// 使用 bitflags 宏定义一个名为 OpenFlags 的位标志集，它用于打开文件时指定标志  
bitflags! {  
    /// 派生 Clone 和 Copy trait，使得 OpenFlags 可以被克隆和按值复制  
    #[derive(Clone, Copy)] 
    pub struct OpenFlags: u32 {  
        // 只读模式  
        const RDONLY = 0; 
        // 只写模式  
        const WRONLY = 1 << 0; 
        // 读写模式  
        const RDWR = 1 << 1;
        // 如果文件不存在则创建它  
        const CREATE = 1 << 6;
        // 将文件截断为零长度  
        const TRUNC = 1 << 10;
        // 作为目录打开  
        const DIRECTORY = 1 << 21;
    }  
}  

/// 根据标志确定读和写的权限  
impl OpenFlags {  
    pub fn read_write(&self) -> (bool, bool) {  
        // 如果标志集为空，则默认为 (true, false)，即只读  
        if self.is_empty() {  
            (true, false)  
        // 如果设置了只写标志  
        } else if self.contains(Self::WRONLY) {  
            (false, true)
        // 否则，默认为读写模式  
        } else {  
            (true, true)
        }  
    }  
}  

/// 从 MapPermission 枚举中创建 OpenFlags 实例  
impl From<MapPermission> for OpenFlags {  
    /// 从 MapPermission 枚举创建一个 OpenFlags 实例  
    fn from(perm: MapPermission) -> Self {  
        // 创建一个空的 OpenFlags 实例 
        let mut flags = OpenFlags::empty();  
        // 如果 MapPermission 包含了读权限  
        if perm.contains(MapPermission::R) {  
            // 如果同时包含写权限，则设置读写模式  
            if perm.contains(MapPermission::W) {  
                flags |= OpenFlags::RDWR; 
            // 否则，只设置只读模式  
            } else {  
                flags |= OpenFlags::RDONLY;
            }
        // 如果只包含写权限，则设置只写模式  
        } else if perm.contains(MapPermission::W) {  
            flags |= OpenFlags::WRONLY; 
        }
        flags  
    }
}

