/// 定义了一个名为 metadata 的字段，类型为 Option<InodeMeta>，表示 Inode 的元数据。
pub struct TestRootInode {
    metadata: Option<InodeMeta>,
}

impl Inode for TestRootInode {
    /// 用于打开文件。
    fn open(
        &self,
        this: Arc<dyn Inode>,
        flags: OpenFlags,
    ) -> Result<alloc::sync::Arc<dyn File>, SyscallErr> {
        let file = TestRootFile {
            metadata: Some(FileMeta {
                path: this.metadata().path.clone(),
                flags,
                inner: SpinMutex::new(FileMetaInner {
                    inode: Some(this.clone()),
                    pos: 0,
                }),
            }),
        };
        Ok(Arc::new(file))
    }
    /// 用于创建目录。
    fn mkdir(
        &self,
        this: Arc<dyn Inode>,
        pathname: &str,
        mode: InodeMode,
    ) -> Result<(), SyscallErr> {
        let mut new_inode = TestRootInode { metadata: None };
        new_inode.init(Some(this.clone()), pathname, mode, 0)?;
        let key = new_inode.metadata().inner.lock().hash_name.name_hash as usize;
        let new_inode = Arc::new(new_inode);
        INODE_CACHE.lock().insert(key, new_inode.clone());
        this.metadata()
            .inner
            .lock()
            .children
            .insert(new_inode.metadata.as_ref().unwrap().name.clone(), new_inode);
        Ok(())
    }
    /// 返回当前 Inode 的元数据的引用。
    fn metadata(&self) -> &super::vfs::inode::InodeMeta {
        &self.metadata.as_ref().unwrap()
    }
    /// 用于设置当前 Inode 的元数据。
    fn set_metadata(&mut self, meta: InodeMeta) {
        self.metadata = Some(meta);
    }
    /// 加载当前 Inode 的子节点。
    fn load_children(&self, _this: Arc<dyn Inode>) {
        todo!()
    }
    /// 删除当前 Inode 的指定子节点。
    fn delete_child(&self, _child_name: &str) {
        todo!()
