//! 此文件用于获取指定 inode 下的所有目录项。
//!
use crate::klib::string_converter::{string_to_array, MAX_NAME_LEN};

use super::inode::Inode;
use alloc::{sync::Arc, vec::Vec};
use core::mem::size_of;

pub const DIRENT_SIZE: u16 = size_of::<Dirent>() as u16;

#[derive(Debug)]
#[repr(C)]
pub struct Dirent {
    pub d_ino: usize,
    pub d_off: isize,
    pub d_reclen: u16,
    pub d_type: u8,
    pub d_name: [u8; MAX_NAME_LEN],
}

impl Dirent {
    /// 获取指定 inode 下的所有目录项
    pub fn get_dirents(inode: Arc<dyn Inode>) -> Vec<Self> {
        let inode_metadata = inode.metadata();
        let children = inode_metadata.inner.lock().children.clone();
        let mut dirents = Vec::new();

        for value in children.values() {
            let dirent = Dirent {
                d_ino: value.metadata().ino,
                d_off: 0,
                d_reclen: DIRENT_SIZE,
                d_type: value.metadata().mode as u8,
                d_name: string_to_array(value.metadata().name.clone()),
            };
            dirents.push(dirent);
        }

        dirents
    }
}

use super::Thread;
use crate::{
    config::{mm::PAGE_SIZE, mm::USER_STACK_SIZE},
    mm::{
        address::VirtAddr, address_space::page_fault_handler::UStackPageFaultHandler,
        address_space::memory_map::MapPermission,
    },
};
use alloc::boxed::Box;
use log::debug;

/// Get ustack bottom by the given tid
fn get_ustack_by_tid(ustack_bottom: usize, tid: usize) -> usize {
    ustack_bottom + tid * (USER_STACK_SIZE + PAGE_SIZE)
}

impl Thread {
    ///
    pub fn ustack_top(&self) -> usize {
        let inner = unsafe { &mut (*self.inner.get()) };
        get_ustack_by_tid(inner.ustack_base, self.tid.0) + USER_STACK_SIZE
    }
}

impl Thread {
    ///
    pub fn alloc_ustack(&self) {
        let inner = unsafe { &mut (*self.inner.get()) };
        let ustack_bottom = get_ustack_by_tid(inner.ustack_base, self.tid.0);
        debug!(
            "ustack: {:#x}, {:#x}",
            ustack_bottom,
            ustack_bottom + USER_STACK_SIZE
        );
        // self.process.inner.lock().memory_set.insert_framed_area(
        //     ustack_bottom.into(),
        //     (ustack_bottom + USER_STACK_SIZE).into(),
        //     MapPermission::R | MapPermission::W | MapPermission::U,
        // );

        self.process.inner_handler(move |proc| {
            if proc
                .memory_set
                .find_vm_area_by_vpn(VirtAddr::from(ustack_bottom).floor())
                .is_some()
            {
                debug!("ustack {:#x} has been added to memory set", ustack_bottom);
                return;
            }
            proc.memory_set.insert_framed_area_lazily(
                ustack_bottom.into(),
                (ustack_bottom + USER_STACK_SIZE).into(),
                MapPermission::R | MapPermission::W | MapPermission::U,
                Some(Box::new(UStackPageFaultHandler {})),
            );
        });
        //     );
    }


    ///
    pub fn dealloc_ustack(&self) {
        debug!("dealloc ustack");
        let inner = unsafe { &mut (*self.inner.get()) };
        let ustack_bottom = get_ustack_by_tid(inner.ustack_base, self.tid.0);
        self.process
            .inner
            .lock()
            .memory_set
            .remove_area_with_start_vpn(ustack_bottom.into());
    }

    ///
    pub fn dealloc_tid(&self) {
        self.process.dealloc_tid(self.tid.0);
    }
}

impl Drop for Thread {
    fn drop(&mut self) {
        debug!("drop a thread(tid {})", self.tid.0);
        // if !self.user_specified_stack {
        self.dealloc_ustack();
        // }
        self.dealloc_tid();
    }
}

